import 'dotenv/config';
import express from 'express';
import { createServer } from 'http';
import { WebSocketServer } from 'ws';
import { useServer } from 'graphql-ws/lib/use/ws';
import { execute, subscribe } from 'graphql';
import { createYoga } from 'graphql-yoga';
import { createPubSub } from '@graphql-yoga/subscription';
import cors from 'cors';
import cookieParser from 'cookie-parser';
import { schema, type Context } from './schema.js';
import prisma from './prisma.js';
import { verifyToken } from './auth.js';
import multer from 'multer';
import path from 'path';
import fs from 'fs';
import crypto from 'crypto';
import { spawn } from 'child_process';
import { createServer } from 'http';
import { execute, subscribe } from 'graphql';
import { WebSocketServer } from 'ws';
import { useServer } from 'graphql-ws/lib/use/ws';

const app = express();

const pubsub = createPubSub();

app.use(cors({
  origin: 'http://localhost:3000',
  credentials: true,
}));
app.use(cookieParser());

const yoga = createYoga<Context>({
  schema,
  graphiql: true,
  cors: {
    origin: 'http://localhost:3000',
    credentials: true,
  },
  context: async ({ request }) => {
    let authHeader: string | undefined | null = null;
    if (request?.headers?.get) {
      authHeader = request.headers.get('authorization');
    } else if (request?.headers) {
      authHeader = (request.headers as any).authorization || (request.headers as any).Authorization;
    }
    if (!authHeader && (request as any).connectionParams) {
      authHeader = (request as any).connectionParams.authorization || (request as any).connectionParams.Authorization;
    }

    let user = null;
    if (authHeader?.startsWith('Bearer ')) {
      const token = authHeader.slice(7);
      const payload = verifyToken(token);
      if (payload) {
        // enrich user with role from DB (userId is now UUID string)
        const dbUser = await prisma.user.findUnique({ where: { id: payload.userId } });
        user = { userId: payload.userId, email: payload.email, role: dbUser?.role };
      }
    }
    return { user, pubsub };
  },
});

// ensure uploads folder exists
const uploadsRoot = path.join(process.cwd(), 'uploads');
fs.mkdirSync(uploadsRoot, { recursive: true });

// serve uploaded files
app.use('/uploads', express.static(uploadsRoot));

app.use('/graphql', yoga as unknown as express.RequestHandler);

const server = createServer(app);

const wsServer = new WebSocketServer({ server, path: '/graphql' });
useServer(
  {
    schema,
    execute,
    subscribe,
    context: async (ctx) => {
      const connectionParams = ctx.connectionParams as Record<string, unknown> | undefined;
      let authHeader: string | undefined | null = null;
      if (connectionParams) {
        authHeader = (connectionParams.authorization as string) || (connectionParams.Authorization as string) || null;
      }

      let user = null;
      if (authHeader?.startsWith('Bearer ')) {
        const token = authHeader.slice(7);
        const payload = verifyToken(token);
        if (payload) {
          const dbUser = await prisma.user.findUnique({ where: { id: payload.userId } });
          user = { userId: payload.userId, email: payload.email, role: dbUser?.role };
        }
      }
      return { user, pubsub };
    },
    onConnect: (ctx) => {
      console.log('[WS] connection attempt', ctx.connectionParams);
    },
    onError: (ctx, msg, errors) => {
      console.error('[WS] connection error', msg, errors);
    },
  },
  wsServer
);

// helper to get authenticated DB user from Authorization header (or null)
async function getAuthUserFromReq(req: express.Request) {
  const authHeader = req.headers['authorization'] as string | undefined;
  if (!authHeader?.startsWith('Bearer ')) return null;
  const token = authHeader.slice(7);
  const payload = verifyToken(token);
  if (!payload) return null;
  const dbUser = await prisma.user.findUnique({ where: { id: payload.userId } }).catch(() => null);
  return dbUser ?? null;
}

// multer storage for avatars
const avatarStorage = multer.diskStorage({
  destination: (req: any, file: any, cb: any) => {
    const dir = path.join(uploadsRoot, 'avatars');
    fs.mkdirSync(dir, { recursive: true });
    cb(null, dir);
  },
  filename: (req: any, file: any, cb: any) => {
    const safe = `${Date.now()}-${file.originalname.replace(/[^a-zA-Z0-9.-]/g, '_')}`;
    cb(null, safe);
  },
});

// allowed mime types and size limits
const ALLOWED_MIMES = ['image/jpeg', 'image/png', 'image/webp', 'image/gif'];
const MAX_FILE_SIZE = 2 * 1024 * 1024; // 2 MB

function avatarFileFilter(req: any, file: any, cb: any) {
  if (!ALLOWED_MIMES.includes(file.mimetype)) {
    const err: any = new Error('Invalid file type');
    err.code = 'INVALID_MIME_TYPE';
    return cb(err, false);
  }
  cb(null, true);
}

const avatarUpload = multer({
  storage: avatarStorage,
  limits: { fileSize: MAX_FILE_SIZE },
  fileFilter: avatarFileFilter,
});

// upload avatar endpoint with explicit error handling
app.post('/upload/avatar', (req, res) => {
  avatarUpload.single('avatar')(req as any, res as any, (err: any) => {
    if (err) {
      if (err.code === 'LIMIT_FILE_SIZE') {
        return res.status(400).json({ error: 'File too large. Max 2MB allowed.' });
      }
      if (err.code === 'INVALID_MIME_TYPE') {
        return res.status(400).json({ error: 'Invalid file type. Allowed: jpg, png, webp, gif.' });
      }
      return res.status(500).json({ error: 'Upload error' });
    }

    const file = (req as any).file;
    if (!file) return res.status(400).json({ error: 'No file uploaded' });
    const url = `/uploads/avatars/${file.filename}`;
    res.json({ url });
  });
});

// attachments upload (images + audio), support multiple files and dedup via checksum+size
const attachmentsStorage = multer.memoryStorage();
const ATTACHMENTS_MIMES = [...ALLOWED_MIMES, 'audio/mpeg', 'audio/mp3', 'audio/wav', 'audio/ogg', 'audio/webm'];
const MAX_ATTACHMENT_SIZE = 10 * 1024 * 1024; // 10 MB
const attachmentsUpload = multer({ storage: attachmentsStorage, limits: { fileSize: MAX_ATTACHMENT_SIZE } });

app.post('/upload/attachments', (req, res) => {
  attachmentsUpload.array('files')(req as any, res as any, async (err: any) => {
    if (err) {
      if (err.code === 'LIMIT_FILE_SIZE') return res.status(400).json({ error: 'File too large. Max 10MB.' });
      return res.status(500).json({ error: 'Upload error' });
    }

    const files = (req as any).files as Array<any> | undefined;
    if (!files || files.length === 0) return res.status(400).json({ error: 'No files uploaded' });

    try {
      const results: any[] = [];
      for (const file of files) {
        if (!ATTACHMENTS_MIMES.includes(file.mimetype)) {
          results.push({ error: 'invalid_mime', originalName: file.originalname });
          continue;
        }
        const buffer: Buffer = file.buffer;
        const size = buffer.length;
        const hash = crypto.createHash('sha256').update(buffer).digest('hex');

        // check existing
        const existing = await prisma.attachment.findFirst({ where: { checksum: hash, size } });
        if (existing) {
          results.push({ existing: true, attachment: existing });
          continue;
        }

        // write to disk
        const dir = path.join(uploadsRoot, 'attachments');
        fs.mkdirSync(dir, { recursive: true });
        const safe = `${Date.now()}-${file.originalname.replace(/[^a-zA-Z0-9.-]/g, '_')}`;
        const outPath = path.join(dir, safe);
        fs.writeFileSync(outPath, buffer);

        const db = await prisma.attachment.create({ data: { filename: file.originalname, path: `/uploads/attachments/${safe}`, mimeType: file.mimetype, checksum: hash, size, data: {} } as any });

        // If audio file, try to extract waveform using ffmpeg (exports PCM s16le to stdout)
        if (file.mimetype && file.mimetype.startsWith('audio/')) {
          try {
            const waveform: number[] = await new Promise((resolve, reject) => {
              const outChunks: Buffer[] = [];
              const ff = spawn('ffmpeg', ['-i', 'pipe:0', '-f', 's16le', '-acodec', 'pcm_s16le', '-ac', '1', '-ar', '44100', 'pipe:1']);
              ff.stdout.on('data', (c: Buffer) => outChunks.push(c));
              // collect stderr to avoid EPIPE issues on some ffmpeg versions
              ff.stderr.on('data', () => { });
              ff.on('error', (err) => reject(err));
              ff.on('close', (code) => {
                try {
                  const raw = Buffer.concat(outChunks);
                  const sampleCount = Math.floor(raw.length / 2);
                  if (sampleCount === 0) return resolve([]);
                  const samples = new Int16Array(raw.buffer, raw.byteOffset, sampleCount);
                  const segments = 40;
                  const segSize = Math.floor(sampleCount / segments) || 1;
                  const wf: number[] = [];
                  for (let i = 0; i < segments; i++) {
                    const start = i * segSize;
                    const end = i === segments - 1 ? sampleCount : start + segSize;
                    let sum = 0;
                    for (let s = start; s < end; s++) {
                      const v = samples[s];
                      sum += v * v;
                    }
                    const rms = Math.sqrt(sum / (end - start)) / 32768;
                    wf.push(Number(rms.toFixed(4)));
                  }
                  return resolve(wf);
                } catch (e) {
                  return reject(e);
                }
              });
              // write buffer to ffmpeg stdin
              ff.stdin.write(buffer);
              ff.stdin.end();
            });

            if (waveform && waveform.length > 0) {
              await prisma.attachment.update({ where: { id: db.id }, data: { data: { waveform } } as any });
              (db as any).data = { waveform };
            }
          } catch (e) {
            // fallback: approximate waveform from raw bytes if ffmpeg isn't available
            try {
              const segments = 40;
              const wf: number[] = [];
              const bytes = buffer;
              const segSize = Math.floor(bytes.length / segments) || 1;
              for (let i = 0; i < segments; i++) {
                const start = i * segSize;
                const end = i === segments - 1 ? bytes.length : start + segSize;
                let sum = 0;
                for (let j = start; j < end; j++) {
                  const v = bytes[j] - 128;
                  sum += v * v;
                }
                const rms = Math.sqrt(sum / (end - start)) / 128;
                wf.push(Number(rms.toFixed(4)));
              }
              await prisma.attachment.update({ where: { id: db.id }, data: { data: { waveform: wf } } as any });
              (db as any).data = { waveform: wf };
            } catch (err) {
              // ignore waveform extraction errors
              console.warn('waveform extraction failed', err);
            }
          }
        }

        results.push({ existing: false, attachment: db });
      }

      return res.json({ attachments: results.map((r) => r.attachment) });
    } catch (e) {
      console.error('upload attachments error', e);
      return res.status(500).json({ error: 'Server error' });
    }
  });
});

function parseMetaTags(html: string, baseUrl: string) {
  const result: Record<string, string> = {};
  const metaRegex = /<meta\s+([^>]+)>/gi;
  let match: RegExpExecArray | null;
  while ((match = metaRegex.exec(html)) !== null) {
    const attrs = match[1];
    const attrRegex = /(property|name|content)\s*=\s*(["'])(.*?)\2/gi;
    let property: string | undefined;
    let name: string | undefined;
    let content: string | undefined;
    let attrMatch: RegExpExecArray | null;
    while ((attrMatch = attrRegex.exec(attrs)) !== null) {
      const key = attrMatch[1].toLowerCase();
      const value = attrMatch[3];
      if (key === 'property') property = value.toLowerCase();
      if (key === 'name') name = value.toLowerCase();
      if (key === 'content') content = value;
    }
    if (content) {
      if (property) {
        result[property] = content;
      } else if (name) {
        result[name] = content;
      }
    }
  }

  if (!result['og:title']) {
    const titleMatch = /<title>([\s\S]*?)<\/title>/i.exec(html);
    if (titleMatch) result['og:title'] = titleMatch[1].trim();
  }

  if (!result['og:description'] && result['description']) {
    result['og:description'] = result['description'];
  }

  if (result['og:image'] && !/^https?:\/\//i.test(result['og:image'])) {
    try {
      result['og:image'] = new URL(result['og:image'], baseUrl).href;
    } catch (err) {
      // ignore invalid relative image URL
    }
  }

  return {
    title: result['og:title'] || '',
    description: result['og:description'] || '',
    image: result['og:image'] || '',
    siteName: result['og:site_name'] || '',
  };
}

app.get('/api/og-preview', async (req, res) => {
  const rawUrl = typeof req.query.url === 'string' ? req.query.url.trim() : '';
  if (!rawUrl) return res.status(400).json({ error: 'Missing url' });

  let parsedUrl: URL;
  try {
    parsedUrl = new URL(rawUrl);
  } catch {
    return res.status(400).json({ error: 'Invalid url' });
  }

  try {
    const response = await fetch(parsedUrl.href, {
      headers: {
        'User-Agent': 'NotAlone/1.0 (+https://localhost)',
        Accept: 'text/html',
      },
    });
    if (!response.ok) {
      return res.status(500).json({ error: 'Unable to fetch preview' });
    }
    const html = await response.text();
    const metadata = parseMetaTags(html, parsedUrl.href);
    return res.json({ url: parsedUrl.href, ...metadata });
  } catch (err) {
    console.error('OG preview error', err);
    return res.status(500).json({ error: 'Preview fetch failed' });
  }
});

const PORT = process.env.PORT || 4000;

server.listen(PORT, () => {
  console.log(`­ƒÜÇ Server ready at http://localhost:${PORT}/graphql`);
  console.log(`­ƒôè GraphiQL available at http://localhost:${PORT}/graphql`);
});

// Public user info (sanitized) - GET /api/v1/users/:id
app.get('/api/v1/users/:id', async (req, res) => {
  try {
    const dbUser = await prisma.user.findUnique({ where: { id: String(req.params.id) }, include: { posts: { orderBy: { createdAt: 'desc' } } } });
    if (!dbUser) return res.status(404).json({ error: 'User not found', code: 'NOT_FOUND' });
    // build minimal public projection
    const publicUser: any = {
      id: dbUser.id,
      username: dbUser.username,
      avatar: dbUser.avatar || null,
      createdAt: dbUser.createdAt.toISOString(),
      posts: (dbUser.posts || []).filter((p: any) => p.isPublic !== false).map((p: any) => ({ id: p.id, content: p.content, createdAt: p.createdAt.toISOString(), isPublic: p.isPublic })),
    };
    return res.json(publicUser);
  } catch (e) {
    console.error('GET /api/v1/users/:id error', e);
    return res.status(500).json({ error: 'Server error', code: 'INTERNAL_ERROR' });
  }
});

// Admin-only full user info - GET /api/v1/admin/users/:id
app.get('/api/v1/admin/users/:id', async (req, res) => {
  try {
    const authUser = await getAuthUserFromReq(req);
    if (!authUser) return res.status(401).json({ error: 'Unauthenticated', code: 'UNAUTHENTICATED' });
    if ((authUser.role || 'USER') !== 'ADMIN') return res.status(403).json({ error: 'Forbidden', code: 'FORBIDDEN' });

    const dbUser = await prisma.user.findUnique({ where: { id: String(req.params.id) } });
    if (!dbUser) return res.status(404).json({ error: 'User not found', code: 'NOT_FOUND' });
    // return full user (do not include password)
    const { password, ...rest } = dbUser as any;
    const out = { ...rest, createdAt: rest.createdAt instanceof Date ? rest.createdAt.toISOString() : rest.createdAt };
    return res.json(out);
  } catch (e) {
    console.error('GET /api/v1/admin/users/:id error', e);
    return res.status(500).json({ error: 'Server error', code: 'INTERNAL_ERROR' });
  }
});

import { Context } from "../schema";

export const ROLE_ORDER: Record<string, number> = {
  USER: 0,
  MODERATOR: 1,
  ADMIN: 2,
};

export function hasRole(context: Context, role: 'USER' | 'MODERATOR' | 'ADMIN') {
  if (!context.user) return false;
  const r = (context.user.role as string) || 'USER';
  return (ROLE_ORDER[r] ?? 0) >= (ROLE_ORDER[role] ?? 0);
}

export function requireAuth(context: Context) {
  if (!context.user) throw new Error('Non authentifi├®');
}

export function requireRole(context: Context, role: 'MODERATOR' | 'ADMIN') {
  if (!hasRole(context, role)) throw new Error('Permission refus├®e');
}

export function sanitizeUserForPublic(user: Record<string, unknown> | null | undefined, context: Context) {
  // New simplified public projection. Returns only public fields and public posts.
  if (!user) return null;
  const u = user as Record<string, unknown>;
  const createdVal = u['createdAt'];
  const createdAtStr = createdVal instanceof Date ? (createdVal as Date).toISOString() : String(createdVal);
  const base: Record<string, unknown> & { posts?: unknown[] } = {
    id: u['id'],
    username: u['username'],
    avatar: u['avatar'] ?? null,
    createdAt: createdAtStr,
  };
  if (u.posts) {
    base.posts = (u.posts as unknown as Array<Record<string, unknown>>)
      .filter((p) => (p as Record<string, unknown>)['isPublic'] !== false)
      .map((p) => sanitizePostForPublic(p as Record<string, unknown>, context));
  }
  // Do NOT expose email, role, or other private fields here.
  return base;
}

export function sanitizePostForPublic(post: Record<string, unknown> | null | undefined, context: Context) {
  if (!post) return post;
  const p = convertDates({ ...(post as Record<string, unknown>) }) as Record<string, unknown>;

  // Ensure author is never null: if missing, provide a deleted-user fallback using authorId
  if (!p['author']) {
    p['author'] = { id: p['authorId'] ?? null, username: 'deleted', createdAt: p['createdAt'] ?? new Date().toISOString() };
  }
  p['author'] = sanitizeUserForPublic(p['author'] as Record<string, unknown>, context) || { id: (p['author'] as Record<string, unknown>)['id'], username: 'deleted', createdAt: String((p['author'] as Record<string, unknown>)['createdAt'] ?? p['createdAt']) };

  if (p['comments']) {
    p['comments'] = (p['comments'] as unknown as Array<Record<string, unknown>>)
      .filter((c) => !(c as any).deleted)
      .map((c) => {
        const cc = c as Record<string, unknown>;
        if (!cc['author']) {
          cc['author'] = { id: cc['authorId'] ?? null, username: 'deleted', createdAt: cc['createdAt'] ?? p['createdAt'] };
        }
        const authorSanitized = sanitizeUserForPublic(cc['author'] as Record<string, unknown>, context);
        return { ...cc, author: authorSanitized || { id: (cc['author'] as Record<string, unknown>)['id'], username: 'deleted', createdAt: String((cc['author'] as Record<string, unknown>)['createdAt'] ?? cc['createdAt'] ?? p['createdAt']) } };
      });
  }

  if (p['likes']) {
    p['likes'] = (p['likes'] as unknown as Array<Record<string, unknown>>).map((l) => {
      const ll = l as Record<string, unknown>;
      if (!ll['user']) {
        ll['user'] = { id: ll['userId'] ?? null, username: 'deleted', createdAt: ll['createdAt'] ?? p['createdAt'] };
      }
      const userSan = sanitizeUserForPublic(ll['user'] as Record<string, unknown>, context);
      return { ...ll, user: userSan || { id: (ll['user'] as Record<string, unknown>)['id'], username: 'deleted', createdAt: String((ll['user'] as Record<string, unknown>)['createdAt'] ?? ll['createdAt'] ?? p['createdAt']) } };
    });
  }

  // Ensure attachments is always an array (GraphQL non-null expectation). Map entries if present, otherwise empty array.
  if (p['attachments']) {
    p['attachments'] = (p['attachments'] as unknown as Array<Record<string, unknown>>).map((a) => {
      const aa = { id: a['id'], filename: a['filename'], path: a['path'], mimeType: a['mimeType'], checksum: a['checksum'], size: a['size'], createdAt: a['createdAt'], data: a['data'] ?? null };
      return aa;
    });
  } else {
    p['attachments'] = [];
  }

  return p;
}

export function convertDates(obj: any): any {
  if (!obj || typeof obj !== 'object') return obj;
  // handle Date -> ISO conversion for known fields
  const out: any = Array.isArray(obj) ? [] : { ...(obj as any) };

  if (Array.isArray(obj)) {
    return (obj as any[]).map(convertDates);
  }

  for (const key of Object.keys(out)) {
    const val = out[key];
    if (val instanceof Date) {
      out[key] = val.toISOString();
    } else if (Array.isArray(val)) {
      out[key] = (val as any[]).map(convertDates);
    } else if (val && typeof val === 'object') {
      out[key] = convertDates(val as any);
    }
  }

  return out;
}

