import { Context } from "./schema";
import { GraphQLScalarType, Kind } from 'graphql';
import { generateToken } from "./auth";
import { convertDates, hasRole, sanitizeUserForPublic, requireRole, sanitizePostForPublic, requireAuth } from "./libs/tools";
import prisma from "./prisma";
import bcrypt from 'bcryptjs';

export const resolvers = {
  JSON: new GraphQLScalarType({
    name: 'JSON',
    description: 'Arbitrary JSON value',
    parseValue: (v) => v,
    serialize: (v) => v,
    parseLiteral: (ast: any) => {
      const parse = (node: any): any => {
        switch (node.kind) {
          case Kind.STRING:
          case Kind.BOOLEAN:
            return node.value;
          case Kind.INT:
          case Kind.FLOAT:
            return Number(node.value);
          case Kind.OBJECT:
            const obj: any = {};
            for (const field of node.fields) {
              obj[field.name.value] = parse(field.value);
            }
            return obj;
          case Kind.LIST:
            return node.values.map(parse);
          case Kind.NULL:
            return null;
          default:
            return null;
        }
      };
      return parse(ast);
    },
  }),
  Query: {
    me: async (_parent: any, _args: any, context: Context) => {
      if (!context.user) return null;
      const u = await prisma.user.findUnique({
        where: { id: context.user.userId },
        include: {
          posts: { orderBy: { createdAt: 'desc' }, where: { deleted: false } as any, include: { author: true, comments: { include: { author: true }, where: { deleted: false } as any }, likes: { include: { user: true } }, attachments: true } },
        },
      });
      return convertDates(u);
    },

    user: async (_parent: any, args: { id: string }, context: Context) => {
      const u = await prisma.user.findUnique({
        where: { id: args.id },
        include: {
          posts: { orderBy: { createdAt: 'desc' }, where: { deleted: false } as any, include: { author: true, comments: { include: { author: true }, where: { deleted: false } as any }, likes: { include: { user: true } }, attachments: true } },
        },
      });
      if (!u) return null;
      // If the requester is admin or the owner, return full user info (without password)
      if (context.user && (hasRole(context, 'MODERATOR') || hasRole(context, 'ADMIN') || context.user.userId === u.id)) {
        const { password, ...rest } = u as any;
        return convertDates(rest);
      }
      // Otherwise return the public projection
      return sanitizeUserForPublic(u, context);
    },

    users: async (_parent: any, _args: any, context: Context) => {
      // only moderators and admins can list full users
      requireRole(context, 'MODERATOR');
      const list = await prisma.user.findMany({ orderBy: { createdAt: 'desc' } });
      return list.map(convertDates);
    },

    posts: async (_parent: any, args: { limit?: number; offset?: number }, context: Context) => {
      const posts = await prisma.post.findMany({
        where: { isPublic: true, deleted: false } as any,
        orderBy: { createdAt: 'desc' },
        take: args.limit ?? 20,
        skip: args.offset ?? 0,
        include: {
          author: true,
          comments: { include: { author: true }, where: { deleted: false } as any, orderBy: { createdAt: 'desc' } },
          likes: { include: { user: true } },
          attachments: true,
        },
      });
      return posts.map((p) => {
        const sanitized = sanitizePostForPublic(p, context) as Record<string, unknown>;
        const liked = context.user ? (p.likes ?? []).some((l: any) => (l.user?.id ?? l.userId) === context.user!.userId) : false;
        return { ...sanitized, isLikedByMe: liked };
      });
    },

    post: async (_parent: any, args: { id: string }, context: Context) => {
      const p = await prisma.post.findUnique({
        where: { id: args.id },
        include: {
          author: true,
          comments: { include: { author: true }, where: { deleted: false } as any, orderBy: { createdAt: 'desc' } },
          likes: { include: { user: true } },
          attachments: true,
        },
      });
      if (!p) return null;
      const sanitized = sanitizePostForPublic(p, context) as Record<string, unknown>;
      const liked = context.user ? (p.likes ?? []).some((l: any) => (l.user?.id ?? l.userId) === context.user!.userId) : false;
      return { ...sanitized, isLikedByMe: liked };
    },

    myPosts: async (_parent: any, _args: any, context: Context) => {
      if (!context.user) throw new Error('Non authentifi├®');
      const posts = await prisma.post.findMany({
        where: { authorId: context.user.userId, deleted: false } as any,
        orderBy: { createdAt: 'desc' },
        include: {
          author: true,
          comments: { include: { author: true }, where: { deleted: false } as any, orderBy: { createdAt: 'desc' } },
          likes: { include: { user: true } },
          attachments: true,
        },
      });
      return posts.map((p) => {
        const sanitized = sanitizePostForPublic(p, context) as Record<string, unknown>;
        const liked = context.user ? (p.likes ?? []).some((l: any) => (l.user?.id ?? l.userId) === context.user!.userId) : false;
        return { ...sanitized, isLikedByMe: liked };
      });
    },

    conversations: async (_parent: any, args: { limit?: number; offset?: number }, context: Context) => {
      requireAuth(context);
      const userId = context.user?.userId!;
      const messages = await prisma.message.findMany({
        where: {
          OR: [
            { senderId: userId },
            { receiverId: userId },
          ],
        },
        orderBy: { createdAt: 'desc' },
        include: { sender: true, receiver: true },
      });

      const unreadByPartner = new Map<string, number>();
      for (const message of messages) {
        if (message.receiverId === userId && !message.read) {
          unreadByPartner.set(message.senderId, (unreadByPartner.get(message.senderId) ?? 0) + 1);
        }
      }

      const seen = new Set<string>();
      const conversations = [] as Array<{
        id: string;
        partner: any;
        lastMessage: string;
        lastMessageAt: string;
        unreadCount: number;
      }>;

      for (const message of messages) {
        const partner = message.senderId === userId ? message.receiver : message.sender;
        const partnerId = partner.id;
        if (seen.has(partnerId)) continue;
        seen.add(partnerId);

        conversations.push({
          id: partnerId,
          partner: sanitizeUserForPublic(partner, context),
          lastMessage: message.content,
          lastMessageAt: message.createdAt.toISOString(),
          unreadCount: unreadByPartner.get(partnerId) ?? 0,
        });
      }

      const start = args.offset ?? 0;
      const size = args.limit ?? 50;
      return conversations.slice(start, start + size);
    },

    messages: async (_parent: any, args: { userId: string }, context: Context) => {
      if (!context.user) throw new Error('Non authentifi├®');
      const msgs = await prisma.message.findMany({
        where: {
          OR: [
            { senderId: context.user.userId, receiverId: args.userId },
            { senderId: args.userId, receiverId: context.user.userId },
          ],
        },
        orderBy: { createdAt: 'asc' },
        include: { sender: true, receiver: true },
      });
      return msgs.map((m) => {
        const mm = convertDates({ ...m });
        return {
          ...mm,
          sender: sanitizeUserForPublic(m.sender, context),
          receiver: sanitizeUserForPublic(m.receiver, context),
        };
      });
    },
    messagesPaginated: async (_parent: any, args: { userId: string; limit?: number; offset?: number }, context: Context) => {
      if (!context.user) throw new Error('Non authentifi├®');
      const msgs = await prisma.message.findMany({
        where: {
          OR: [
            { senderId: context.user.userId, receiverId: args.userId },
            { senderId: args.userId, receiverId: context.user.userId },
          ],
        },
        orderBy: { createdAt: 'desc' },
        take: args.limit ?? 50,
        skip: args.offset ?? 0,
        include: { sender: true, receiver: true },
      });
      return msgs.map((m) => {
        const mm = convertDates({ ...m });
        return {
          ...mm,
          sender: sanitizeUserForPublic(m.sender, context),
          receiver: sanitizeUserForPublic(m.receiver, context),
        };
      });
    },

    notifications: async (_parent: any, args: { limit?: number; offset?: number }, context: Context) => {
      if (!context.user) throw new Error('Non authentifi├®');
      const notes = await prisma.notification.findMany({
        where: { userId: context.user.userId },
        orderBy: { createdAt: 'desc' },
        take: args.limit ?? 20,
        skip: args.offset ?? 0,
        include: { author: true, user: true },
      });
      return notes.map((n) => {
        const nn = convertDates(n as any) as any;
        return {
          ...nn,
          author: sanitizeUserForPublic((n as any).author, context),
          user: sanitizeUserForPublic((n as any).user, context),
        };
      });
    },
  },

  Mutation: {
    register: async (_parent: any, args: { email: string; username: string; password: string; firstName?: string; lastName?: string }) => {
      const existing = await prisma.user.findFirst({
        where: { OR: [{ email: args.email }, { username: args.username }] },
      });
      if (existing) {
        throw new Error('Un utilisateur avec cet email ou ce nom existe d├®j├á');
      }

      const hashedPassword = await bcrypt.hash(args.password, 12);
      const user = await prisma.user.create({
        data: {
          email: args.email,
          username: args.username,
          password: hashedPassword,
          firstName: args.firstName,
          lastName: args.lastName,
        },
      });

      const token = generateToken({ userId: user.id, email: user.email });
      return { token, user: convertDates(user) };
    },

    login: async (_parent: any, args: { identifier: string; password: string }, context: Context) => {
      const user = await prisma.user.findFirst({
        where: {
          OR: [{ email: args.identifier }, { username: args.identifier }],
        },
      });
      if (!user) {
        throw new Error('Identifiants invalides');
      }

      const valid = await bcrypt.compare(args.password, user.password);
      if (!valid) {
        throw new Error('Identifiants invalides');
      }

      const token = generateToken({ userId: user.id, email: user.email });
      return { token, user: convertDates(user) };
    },

    createPost: async (_parent: any, args: { content: string; mood?: string; isPublic?: boolean; attachmentIds?: string[]; payload?: any }, context: Context) => {
      if (!context.user) throw new Error('Non authentifi├®');
      const data: any = {
        content: args.content,
        mood: args.mood,
        isPublic: args.isPublic ?? true,
        authorId: context.user.userId,
      };
      if (args.attachmentIds && args.attachmentIds.length > 0) {
        data.attachments = { connect: args.attachmentIds.map((id: string) => ({ id })) };
      }
      if (args.payload !== undefined) {
        data.payload = args.payload;
      }
      const created = await prisma.post.create({
        data,
        include: {
          author: true,
          comments: { include: { author: true }, orderBy: { createdAt: 'desc' } },
          likes: { include: { user: true } },
          attachments: true,
        },
      });
      const sanitized = sanitizePostForPublic(created, context);
      await context.pubsub.publish('post', sanitized);
      await context.pubsub.publish(`post:user:${context.user.userId}`, sanitized);
      return sanitized;
    },

    deletePost: async (_parent: any, args: { id: string }, context: Context) => {
      requireAuth(context);
      const post = await prisma.post.findUnique({ where: { id: args.id } });
      if (!post) throw new Error('Post introuvable');
      // allow if author or moderator/admin
      if (post.authorId !== context.user!.userId && !hasRole(context, 'MODERATOR') && !hasRole(context, 'ADMIN')) {
        throw new Error('Non autoris├®');
      }
      await prisma.$transaction([
        prisma.post.update({ where: { id: args.id }, data: { deleted: true } as any } as any),
        prisma.comment.updateMany({ where: { postId: args.id }, data: { deleted: true } as any } as any),
      ] as any);
      return true;
    },

    updatePost: async (_parent: any, args: { id: string; content: string }, context: Context) => {
      requireAuth(context);
      const post = await prisma.post.findUnique({ where: { id: args.id } });
      if (!post || (post as any).deleted) throw new Error('Post introuvable');
      if (post.authorId !== context.user!.userId && !hasRole(context, 'MODERATOR') && !hasRole(context, 'ADMIN')) {
        throw new Error('Non autoris├®');
      }
      const updated = await prisma.post.update({
        where: { id: args.id },
        data: { content: args.content },
        include: {
          author: true,
          comments: { include: { author: true }, where: { deleted: false } as any, orderBy: { createdAt: 'desc' } },
          likes: { include: { user: true } },
          attachments: true,
        },
      });
      const sanitized = sanitizePostForPublic(updated, context) as Record<string, unknown>;
      const liked = context.user ? (updated.likes ?? []).some((l: any) => (l.user?.id ?? l.userId) === context.user!.userId) : false;
      return { ...sanitized, isLikedByMe: liked };
    },

    updateComment: async (_parent: any, args: { id: string; content: string }, context: Context) => {
      requireAuth(context);
      const comment = await prisma.comment.findUnique({ where: { id: args.id } });
      if (!comment || (comment as any).deleted) throw new Error('Commentaire introuvable');
      if (comment.authorId !== context.user!.userId && !hasRole(context, 'MODERATOR') && !hasRole(context, 'ADMIN')) {
        throw new Error('Non autoris├®');
      }
      const updated = await prisma.comment.update({
        where: { id: args.id },
        data: { content: args.content },
        include: { author: true, post: true },
      });
      return { ...convertDates(updated), author: sanitizeUserForPublic(updated.author, context) };
    },

    deleteComment: async (_parent: any, args: { id: string }, context: Context) => {
      requireAuth(context);
      const comment = await prisma.comment.findUnique({ where: { id: args.id } });
      if (!comment || (comment as any).deleted) throw new Error('Commentaire introuvable');
      if (comment.authorId !== context.user!.userId && !hasRole(context, 'MODERATOR') && !hasRole(context, 'ADMIN')) {
        throw new Error('Non autoris├®');
      }
      await prisma.comment.update({ where: { id: args.id }, data: { deleted: true } as any } as any);
      return true;
    },

    createComment: async (_parent: any, args: { postId: string; content: string }, context: Context) => {
      if (!context.user) throw new Error('Non authentifi├®');
      const post = await prisma.post.findUnique({ where: { id: args.postId } });
      if (!post || (post as any).deleted) throw new Error('Post introuvable');
      const created = await prisma.comment.create({
        data: {
          content: args.content,
          authorId: context.user.userId,
          postId: args.postId,
        },
        include: { author: true, post: true },
      });
      // create notification for post author (if not commenting on own post)
      try {
        const postAuthorId = (created.post as any).authorId as string;
        if (postAuthorId && postAuthorId !== context.user.userId) {
          const notification = await prisma.notification.create({
            data: {
              userId: postAuthorId,
              authorId: context.user.userId,
              type: 'NEW_COMMENT',
              linkId: args.postId,
            },
            include: { author: true, user: true },
          });
          await context.pubsub.publish(`notification:${postAuthorId}`, convertDates(notification));
        }
      } catch (e) {
        // ignore notification creation errors
      }
      const c = convertDates(created);
      const commentPayload = { ...c, author: sanitizeUserForPublic(created.author, context), post: { id: args.postId } } as any;
      try {
        await context.pubsub.publish('comment', commentPayload);
        await context.pubsub.publish(`comment:post:${args.postId}`, commentPayload);
        const postAuthorId = (created.post as any).authorId as string | undefined;
        if (postAuthorId) {
          await context.pubsub.publish(`comment:user:${postAuthorId}`, commentPayload);
        }
      } catch (err) {
        console.error('[Subscription] Failed to publish comment event', err);
      }
      return { ...c, author: sanitizeUserForPublic(created.author, context) };
    },

    toggleLike: async (_parent: any, args: { postId: string }, context: Context) => {
      if (!context.user) throw new Error('Non authentifi├®');
      const existing = await prisma.like.findUnique({
        where: {
          userId_postId: {
            userId: context.user.userId,
            postId: args.postId,
          },
        },
      });
      if (existing) {
        await prisma.like.delete({ where: { id: existing.id } });
        return false;
      }
      const createdLike = await prisma.like.create({ data: { userId: context.user.userId, postId: args.postId } });
      // create notification for post author (if not liking own post)
      try {
        const post = await prisma.post.findUnique({ where: { id: args.postId } });
        if (post && post.authorId !== context.user.userId) {
          const notification = await prisma.notification.create({
            data: {
              userId: post.authorId,
              authorId: context.user.userId,
              type: 'NEW_LIKE',
              linkId: args.postId,
            },
            include: { author: true, user: true },
          });
          await context.pubsub.publish(`notification:${post.authorId}`, convertDates(notification));
        }
      } catch (e) {
        // ignore
      }
      return true;
    },

    sendMessage: async (_parent: any, args: { receiverId: string; content: string }, context: Context) => {
      if (!context.user) throw new Error('Non authentifi├®');
      const created = await prisma.message.create({
        data: {
          content: args.content,
          senderId: context.user.userId,
          receiverId: args.receiverId,
        },
        include: { sender: true, receiver: true },
      });
      const m = convertDates(created);
      const payload = { ...m, sender: sanitizeUserForPublic(created.sender, context), receiver: sanitizeUserForPublic(created.receiver, context) };
      try {
        await context.pubsub.publish(`message:${args.receiverId}`, payload);
        console.log(`[Subscription] Published message event for receiver ${args.receiverId} from sender ${context.user.userId}`);
      } catch (err) {
        console.error('[Subscription] Failed to publish message event', err);
      }
      return payload;
    },

    setTypingStatus: async (_parent: any, args: { receiverId: string; isTyping: boolean }, context: Context) => {
      if (!context.user) throw new Error('Non authentifi├®');
      console.log(`[Subscription] setTypingStatus resolver called for receiver ${args.receiverId} from sender ${context.user.userId} isTyping=${args.isTyping}`);
      const receiver = await prisma.user.findUnique({ where: { id: args.receiverId } });
      if (!receiver) throw new Error('Utilisateur introuvable');
      const payload = {
        sender: (await prisma.user.findUnique({ where: { id: context.user.userId } }))!,
        receiver,
        isTyping: args.isTyping,
      };
      try {
        await context.pubsub.publish(`typing:${args.receiverId}`, payload);
        console.log(`[Subscription] Published typing event for receiver ${args.receiverId} from sender ${context.user.userId} isTyping=${args.isTyping}`);
      } catch (err) {
        console.error('[Subscription] Failed to publish typing event', err);
      }
      return true;
    },

    markMessageRead: async (_parent: any, args: { id: string }, context: Context) => {
      requireAuth(context);
      const message = await prisma.message.findUnique({ where: { id: args.id } });
      if (!message) throw new Error('Message introuvable');
      // only receiver, moderator or admin can mark as read
      if (message.receiverId !== context.user!.userId && !hasRole(context, 'MODERATOR') && !hasRole(context, 'ADMIN')) {
        throw new Error('Non autoris├®');
      }
      const updated = await prisma.message.update({
        where: { id: args.id },
        data: { read: true },
        include: { sender: true, receiver: true },
      });
      const mu = convertDates(updated);
      return { ...mu, sender: sanitizeUserForPublic(updated.sender, context), receiver: sanitizeUserForPublic(updated.receiver, context) };
    },

    markNotificationRead: async (_parent: any, args: { id: string }, context: Context) => {
      requireAuth(context);
      const note = await prisma.notification.findUnique({ where: { id: args.id } });
      if (!note) throw new Error('Notification introuvable');
      if (note.userId !== context.user!.userId && !hasRole(context, 'MODERATOR') && !hasRole(context, 'ADMIN')) {
        throw new Error('Non autoris├®');
      }
      const updated = await prisma.notification.update({ where: { id: args.id }, data: { read: true }, include: { author: true, user: true } });
      const nn = convertDates(updated as any) as any;
      return { ...nn, author: sanitizeUserForPublic(updated.author, context), user: sanitizeUserForPublic(updated.user, context) };
    },

    updateProfile: async (_parent: any, args: { firstName?: string; lastName?: string; bio?: string; avatar?: string; userId?: string }, context: Context) => {
      requireAuth(context);
      // allow admin to update any profile by passing userId
      let targetId = context.user!.userId;
      if (args.userId && args.userId !== context.user!.userId) {
        if (!hasRole(context, 'ADMIN')) throw new Error('Non autoris├®');
        targetId = args.userId;
      }
      const u = await prisma.user.update({ where: { id: targetId }, data: { firstName: args.firstName, lastName: args.lastName, bio: args.bio, avatar: args.avatar } });
      return convertDates(u);
    },
    updateUserRole: async (_parent: any, args: { userId: string; role: string }, context: Context) => {
      // only admin can change roles
      requireAuth(context);
      if (!hasRole(context, 'ADMIN')) throw new Error('Non autoris├®');
      const allowed = ['USER', 'MODERATOR', 'ADMIN'];
      if (!allowed.includes(args.role)) throw new Error('Role invalide');
      const u = await prisma.user.update({ where: { id: args.userId }, data: { role: args.role as any } });
      return convertDates(u);
    },

    deleteUser: async (_parent: any, args: { id: string }, context: Context) => {
      requireAuth(context);
      if (!hasRole(context, 'ADMIN')) throw new Error('Non autoris├®');
      // delete user cascade will remove related content per Prisma schema
      await prisma.user.delete({ where: { id: args.id } });
      return true;
    },
  },

  Subscription: {
    notificationReceived: {
      subscribe: async (_parent: any, args: { userId: string }, context: Context) => {
        if (!context.user) throw new Error('Non authentifi├®');
        if (context.user.userId !== args.userId) throw new Error('Non autoris├®');
        console.log(`[Subscription] notificationReceived subscribed for user ${args.userId}`);
        return context.pubsub.subscribe(`notification:${args.userId}`);
      },
      resolve: (payload: any) => payload,
    },
    messageReceived: {
      subscribe: async (_parent: any, args: { userId: string }, context: Context) => {
        if (!context.user) throw new Error('Non authentifi├®');
        if (context.user.userId !== args.userId) throw new Error('Non autoris├®');
        console.log(`[Subscription] messageReceived subscribed for user ${args.userId}`);
        return context.pubsub.subscribe(`message:${args.userId}`);
      },
      resolve: (payload: any) => payload,
    },
    typingStatus: {
      subscribe: async (_parent: any, args: { userId: string }, context: Context) => {
        if (!context.user) throw new Error('Non authentifi├®');
        if (context.user.userId !== args.userId) throw new Error('Non autoris├®');
        console.log(`[Subscription] typingStatus subscribed for user ${args.userId}`);
        return context.pubsub.subscribe(`typing:${args.userId}`);
      },
      resolve: (payload: any) => payload,
    },
    commentCreated: {
      subscribe: async (_parent: any, args: { postId?: string; userId?: string }, context: Context) => {
        if (!context.user) throw new Error('Non authentifi├®');
        if (args.postId) {
          const post = await prisma.post.findUnique({ where: { id: args.postId }, select: { id: true, isPublic: true, authorId: true } });
          if (!post) throw new Error('Post introuvable');
          if (!post.isPublic && post.authorId !== context.user.userId && !hasRole(context, 'ADMIN') && !hasRole(context, 'MODERATOR')) {
            throw new Error('Non autoris├® ├á voir ce post');
          }
          console.log(`[Subscription] commentCreated subscribed for post ${args.postId}`);
          return context.pubsub.subscribe(`comment:post:${args.postId}`);
        }
        if (args.userId) {
          console.log(`[Subscription] commentCreated subscribed for user ${args.userId}`);
          return context.pubsub.subscribe(`comment:user:${args.userId}`);
        }
        console.log('[Subscription] commentCreated subscribed globally');
        return context.pubsub.subscribe('comment');
      },
      resolve: (payload: any) => payload,
    },
    postCreated: {
      subscribe: async (_parent: any, args: { userId?: string }, context: Context) => {
        if (!context.user) throw new Error('Non authentifi├®');
        if (args.userId) {
          console.log(`[Subscription] postCreated subscribed for user ${args.userId}`);
          return context.pubsub.subscribe(`post:user:${args.userId}`);
        }
        console.log('[Subscription] postCreated subscribed globally');
        return context.pubsub.subscribe('post');
      },
      resolve: (payload: any) => payload,
    },
  },

  Post: {
    likesCount: (parent: { likes?: unknown[] }) => parent.likes?.length ?? 0,
    commentsCount: (parent: { comments?: unknown[] }) => parent.comments?.length ?? 0,
    isLikedByMe: (parent: { likes?: Array<{ user: { id: string } }> }, _args: unknown, context: Context) => {
      if (!context.user) return false;
      return parent.likes?.some((like) => like.user.id === context.user!.userId) ?? false;
    },
  },

  User: {
    posts: async (parent: Record<string, unknown>, _args: unknown, context: Context) => {
      // if posts were already loaded on the parent (e.g., included), use them (sanitized)
      if (parent['posts']) {
        return (parent['posts'] as unknown as Array<Record<string, unknown>>).map((p) => sanitizePostForPublic(p as Record<string, unknown>, context));
      }
      const posts = await prisma.post.findMany({
        where: { authorId: parent['id'] as string },
        orderBy: { createdAt: 'desc' },
        include: { author: true, comments: { include: { author: true } }, likes: { include: { user: true } }, attachments: true },
      });
      return posts.map((p) => sanitizePostForPublic(p, context));
    },
  },
}

import { createSchema } from 'graphql-yoga';
import bcrypt from 'bcryptjs';
import prisma from './prisma.js';
import { generateToken, type TokenPayload } from './auth.js';
import { resolvers } from './resolvers.js';
import { typeDefs } from './typeDefs.js';

export interface Context {
  user: (TokenPayload & { role?: string }) | null;
  pubsub: any;
}

export const schema = createSchema<Context>({
  typeDefs: typeDefs,
  resolvers: resolvers,
});

import { Avatar, Badge, Box, Card, Collapse, Divider, Group, Skeleton, Stack, Text, Textarea, ActionIcon } from '@mantine/core';
import { IconX } from '@tabler/icons-react';
import { useEffect, useLayoutEffect, useMemo, useRef, useState } from 'react';
import { useInfiniteMessages, useSendMessage, useSetTypingStatus, useMarkMessageRead } from '@/hooks/useApi';
import type { Message } from '@/types';

type ChatComponentProps = {
  conversationId: string;
  avatar: string;
  username: string;
  lastMessage: string;
  collapsed: boolean;
  onToggleCollapse: () => void;
  onClose?: () => void;
  isTyping?: boolean;
};

export default function ChatComponent({
  conversationId,
  avatar,
  username,
  lastMessage,
  collapsed,
  onToggleCollapse,
  onClose,
  isTyping = false,
}: ChatComponentProps) {
  const [reply, setReply] = useState('');
  const {
    data,
    isLoading,
    fetchNextPage,
    hasNextPage,
    isFetchingNextPage,
  } = useInfiniteMessages(conversationId, 50);
  const sendMessage = useSendMessage();
  const setTypingStatus = useSetTypingStatus();
  const markMessageRead = useMarkMessageRead();
  const setTypingStatusRef = useRef(setTypingStatus);
  const stopTypingTimer = useRef<number | null>(null);
  const isTypingLocalRef = useRef(false);
  const messagesContainerRef = useRef<HTMLDivElement | null>(null);
  const isScrolledToBottomRef = useRef(true);
  const hasScrolledToBottomRef = useRef(false);
  const previousCollapsedRef = useRef(collapsed);
  const previousScrollHeightRef = useRef<number | null>(null);
  const messageRefs = useRef<Record<string, HTMLDivElement | null>>({});
  const alreadyMarkedReadRef = useRef<Set<string>>(new Set());

  useEffect(() => {
    setTypingStatusRef.current = setTypingStatus;
  }, [setTypingStatus]);

  const messages = useMemo<Message[]>(() => {
    const pages = (data as any)?.pages ?? [];
    if (!pages.length) return [];
    return pages
      .slice()
      .reverse()
      .flatMap((page: any) => (Array.isArray(page?.messages) ? [...page.messages].reverse() : []));
  }, [data]);
  const unreadCount = messages.filter((message: Message) => message.receiver.id !== conversationId && !message.read).length;

  const lastMessageLabel = useMemo(
    () => messages[messages.length - 1]?.content ?? lastMessage,
    [lastMessage, messages]
  );

  const sendTypingStatus = async (isTyping: boolean) => {
    try {
      await setTypingStatusRef.current.mutateAsync({ receiverId: conversationId, isTyping });
    } catch (error) {
      console.error('[Chat] failed to update typing status', { conversationId, isTyping }, error);
    }
  };

  const resetTypingTimeout = () => {
    if (stopTypingTimer.current) {
      window.clearTimeout(stopTypingTimer.current);
    }
    stopTypingTimer.current = window.setTimeout(async () => {
      if (isTypingLocalRef.current) {
        await sendTypingStatus(false);
        isTypingLocalRef.current = false;
      }
      stopTypingTimer.current = null;
    }, 3000);
  };

  const formatMessageTime = (iso: string) => {
    const date = new Date(iso);
    const hours = String(date.getHours()).padStart(2, '0');
    const minutes = String(date.getMinutes()).padStart(2, '0');
    return `${hours}:${minutes}`;
  };

  const formatMessageDate = (iso: string) => {
    const date = new Date(iso);
    return date.toLocaleDateString('fr-FR', {
      weekday: 'long',
      day: 'numeric',
      month: 'long',
      year: 'numeric',
    });
  };

  const markVisibleUnreadMessagesRead = () => {
    const container = messagesContainerRef.current;
    if (!container) return;
    const containerRect = container.getBoundingClientRect();

    messages.forEach((message) => {
      if (message.read) return;
      if (message.receiver.id === conversationId && message.sender.id !== message.receiver.id) return;
      if (alreadyMarkedReadRef.current.has(message.id)) return;

      const messageEl = messageRefs.current[message.id];
      if (!messageEl) return;
      const rect = messageEl.getBoundingClientRect();
      const isVisible = rect.bottom > containerRect.top && rect.top < containerRect.bottom;
      if (isVisible) {
        alreadyMarkedReadRef.current.add(message.id);
        markMessageRead.mutate({ id: message.id });
      }
    });
  };

  useEffect(() => {
    const el = messagesContainerRef.current;
    if (!el) return;
    const handleScroll = () => {
      isScrolledToBottomRef.current = el.scrollHeight - el.scrollTop - el.clientHeight <= 8;
      if (el.scrollTop <= 16 && hasNextPage && !isFetchingNextPage) {
        previousScrollHeightRef.current = el.scrollHeight;
        void fetchNextPage();
      }
      markVisibleUnreadMessagesRead();
    };
    el.addEventListener('scroll', handleScroll, { passive: true });
    handleScroll();
    return () => {
      el.removeEventListener('scroll', handleScroll);
    };
  }, [fetchNextPage, hasNextPage, isFetchingNextPage, messages]);

  useEffect(() => {
    markVisibleUnreadMessagesRead();
  }, [messages]);

  const pageCount = (data as any)?.pages?.length;

  useEffect(() => {
    const el = messagesContainerRef.current;
    if (!el || previousScrollHeightRef.current === null) return;
    const addedHeight = el.scrollHeight - previousScrollHeightRef.current;
    if (addedHeight > 0) {
      el.scrollTop = addedHeight;
    }
    previousScrollHeightRef.current = null;
  }, [pageCount]);

  const scrollToBottom = () => {
    const el = messagesContainerRef.current;
    if (!el) return;
    el.scrollTop = el.scrollHeight - el.clientHeight;
  };

  useLayoutEffect(() => {
    const el = messagesContainerRef.current;
    if (!el) return;

    const openedConversation = previousCollapsedRef.current && !collapsed;
    previousCollapsedRef.current = collapsed;

    if (!hasScrolledToBottomRef.current || openedConversation || isScrolledToBottomRef.current) {
      window.requestAnimationFrame(() => {
        window.requestAnimationFrame(scrollToBottom);
      });
      hasScrolledToBottomRef.current = true;
    }
  }, [messages.length, isTyping, collapsed]);

  const handleTyping = () => {
    if (!isTypingLocalRef.current) {
      isTypingLocalRef.current = true;
      void sendTypingStatus(true);
    }
    resetTypingTimeout();
  };

  const handleSend = async () => {
    const trimmed = reply.trim();
    if (!trimmed) return;

    try {
      await sendMessage.mutateAsync({ receiverId: conversationId, content: trimmed });
      setReply('');
      if (stopTypingTimer.current) {
        window.clearTimeout(stopTypingTimer.current);
        stopTypingTimer.current = null;
      }
      if (isTypingLocalRef.current) {
        await sendTypingStatus(false);
        isTypingLocalRef.current = false;
      }
    } catch {
      // ignore send failures for now
    }
  };

  useEffect(() => {
    return () => {
      if (stopTypingTimer.current) {
        window.clearTimeout(stopTypingTimer.current);
      }
      if (isTypingLocalRef.current) {
        void setTypingStatusRef.current.mutateAsync({ receiverId: conversationId, isTyping: false });
        isTypingLocalRef.current = false;
      }
    };
  }, [conversationId]);

  return (
    <Card radius="xl" withBorder style={{ width: 320 }}>
      <Group
        wrap="nowrap"
        align="center"
        gap="md"
        style={{ cursor: 'pointer', display: 'flex', justifyContent: 'space-between', width: '100%' }}
        onClick={onToggleCollapse}
      >
        <Group wrap="nowrap" align="center" gap="md">
          <div style={{ position: 'relative', display: 'inline-flex' }}>
            <Avatar src={avatar} alt={username} radius="xl" size="sm" />
            {unreadCount > 0 ? (
              <Badge
                size="xs"
                variant="filled"
                color="red"
                style={{ position: 'absolute', top: -6, right: -6, minWidth: 18, height: 18, padding: '0 6px' }}
              >
                {unreadCount}
              </Badge>
            ) : null}
          </div>
          <div>
            <Text fw={700}>{username}</Text>
          </div>
        </Group>

        {onClose ? (
          <ActionIcon
            size="xs"
            variant="outline"
            onClick={(event) => {
              event.stopPropagation();
              onClose();
            }}
          >
            <IconX size={16} />
          </ActionIcon>
        ) : null}
      </Group>

      <Collapse in={!collapsed}>
        <Divider my="md" />

        <Stack gap="sm">
          <Box
            ref={messagesContainerRef}
            style={{
              maxHeight: 240,
              overflowY: 'auto',
              display: 'flex',
              flexDirection: 'column',
              gap: 10,
            }}
          >
            {isLoading ? (
              <Text size="sm" c="dimmed">
                Chargement...
              </Text>
            ) : messages.length === 0 ? (
              isTyping ? (
                <Group style={{ justifyContent: 'flex-start' }}>
                  <Box
                    style={{
                      background: '#f1f3f5',
                      padding: '10px 14px',
                      borderRadius: '18px',
                      maxWidth: '65%',
                      boxShadow: '0 1px 2px rgba(16, 42, 67, 0.08)',
                      border: '1px solid rgba(16, 42, 67, 0.12)',
                    }}
                  >
                    <Skeleton height={22} width="100%" radius="xl" animate />
                  </Box>
                </Group>
              ) : (
                <Text size="sm" c="dimmed">
                  Aucune discussion pour l'instant.
                </Text>
              )
            ) : (
              <>
                {(() => {
                  let lastMessageDate = '';
                  return messages.map((message) => {
                    const isMine = message.sender.id !== conversationId;
                    const timeLabel = formatMessageTime(message.createdAt);
                    const messageDate = new Date(message.createdAt).toLocaleDateString('fr-FR');
                    const showDateHeader = messageDate !== lastMessageDate;
                    if (showDateHeader) {
                      lastMessageDate = messageDate;
                    }

                    return (
                      <div key={message.id}>
                        {showDateHeader ? (
                          <Box style={{ width: '100%', display: 'flex', justifyContent: 'center', marginBottom: 6 }}>
                            <Text size="xs" c="dimmed" ta="center" style={{ textTransform: 'capitalize' }}>
                              {formatMessageDate(message.createdAt)}
                            </Text>
                          </Box>
                        ) : null}
                        <Group
                          style={{
                            justifyContent: isMine ? 'flex-end' : 'flex-start',
                            alignItems: 'center',
                            gap: 8,
                          }}
                        >
                          {isMine ? (
                            <Text size="xs" c="dimmed" style={{ minWidth: 40, textAlign: 'right' }}>
                              {timeLabel}
                            </Text>
                          ) : null}
                          <Box
                            ref={(el) => {
                              messageRefs.current[message.id] = el;
                            }}
                            style={{
                              background: isMine ? '#d6f0ff' : '#f1f3f5',
                              color: '#102a43',
                              padding: '10px 14px',
                              borderRadius: '18px',
                              maxWidth: '80%',
                              wordBreak: 'break-word',
                              boxShadow: isMine ? '0 1px 3px rgba(16, 42, 67, 0.12)' : '0 1px 2px rgba(16, 42, 67, 0.08)',
                              border: isMine ? '1px solid rgba(16, 42, 67, 0.08)' : '1px solid rgba(16, 42, 67, 0.12)',
                            }}
                          >
                            <Text size="sm" style={{ whiteSpace: 'pre-wrap' }}>{message.content}</Text>
                          </Box>
                          {!isMine ? (
                            <Text size="xs" c="dimmed" style={{ minWidth: 40, textAlign: 'left' }}>
                              {timeLabel}
                            </Text>
                          ) : null}
                        </Group>
                      </div>
                    );
                  });
                })()}
                {isTyping ? (
                  <Group style={{ justifyContent: 'flex-start', width: '100%' }}>
                    <Box
                      style={{
                        background: '#f1f3f5',
                        padding: '10px 14px',
                        borderRadius: '18px',
                        maxWidth: '75%',
                        minWidth: 140,
                        width: '75%',
                        boxShadow: '0 1px 2px rgba(16, 42, 67, 0.08)',
                        border: '1px solid rgba(16, 42, 67, 0.12)',
                      }}
                    >
                      <Text size="sm" c="dimmed" style={{fontStyle:"italic"}}>
                        {username} est en train d'├®crire...
                      </Text>
                    </Box>
                  </Group>
                ) : null}
              </>
            )}
          </Box>

          <Divider my="sm" />

          <Stack gap="xs">
            <Textarea
              value={reply}
              onChange={(event) => {
                const newValue = event.currentTarget.value;
                const isDeletion = newValue.length < reply.length;
                setReply(newValue);
                if (!isDeletion) {
                  handleTyping();
                }
              }}
              onKeyDown={(event) => {
                if (event.key === 'Enter') {
                  if (event.shiftKey) {
                    return;
                  }
                  event.preventDefault();
                  handleSend();
                }
              }}
              placeholder="├ëcrire..."
              minRows={2}
              autosize
            />
          </Stack>
        </Stack>
      </Collapse>
    </Card>
  );
}

import { Box, Loader } from '@mantine/core';
import { useEffect, useMemo, useState } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import ChatComponent from './ChatComponent';
import ChatListComponent from './ChatListComponent';
import { useChatSubscriptions, useConversations } from '@/hooks/useApi';

type OpenConversation = {
  id: string;
  username: string;
  avatar: string;
  lastMessage: string;
  lastMessageAt?: string;
  unreadCount?: number;
  collapsed?: boolean;
  isTyping?: boolean;
};

const OPEN_CONVERSATIONS_STORAGE_KEY = 'notalone_open_conversations';

export default function ChatWidget() {
  const [collapsed, setCollapsed] = useState(false);
  const [showOnlyAvatar, setShowOnlyAvatar] = useState(false);
  const [openConversations, setOpenConversations] = useState<OpenConversation[]>([]);
  const [hasRestoredState, setHasRestoredState] = useState(false);

  const conversationsQuery = useConversations(50, 0);

  const { user, token } = useAuth();

  const conversations = useMemo(
    () =>
      conversationsQuery.data?.conversations.map((conversation) => ({
        id: conversation.id,
        username: conversation.partner.username,
        avatar: conversation.partner.avatar ?? '',
        lastMessage: conversation.lastMessage,
        lastMessageAt: conversation.lastMessageAt,
        unreadCount: conversation.unreadCount,
      })) ?? [],
    [conversationsQuery.data]
  );

  useEffect(() => {
    if (hasRestoredState || !conversationsQuery.isSuccess) return;

    try {
      const savedValue = localStorage.getItem(OPEN_CONVERSATIONS_STORAGE_KEY);
      if (!savedValue) {
        setHasRestoredState(true);
        return;
      }

      const parsed = JSON.parse(savedValue) as
        | {
            openConversations?: Array<{ id: string; collapsed?: boolean }>;
            collapsed?: boolean | string;
            showOnlyAvatar?: boolean | string;
          }
        | null;

      const savedOpenConversations = Array.isArray(parsed?.openConversations) ? parsed.openConversations : [];
      const restoredOpenConversations = savedOpenConversations.flatMap((item) => {
        const conversation = conversations.find((c) => c.id === item.id);
        if (!conversation) return [];
        return [{ ...conversation, collapsed: Boolean(item.collapsed) }];
      });

      if (restoredOpenConversations.length > 0) {
        setOpenConversations(restoredOpenConversations);
      }

      if (parsed?.collapsed !== undefined) {
        setCollapsed(parsed.collapsed === true || parsed.collapsed === 'true');
      }
      if (parsed?.showOnlyAvatar !== undefined) {
        setShowOnlyAvatar(parsed.showOnlyAvatar === true || parsed.showOnlyAvatar === 'true');
      }
    } catch {
      // ignore invalid stored value
    } finally {
      setHasRestoredState(true);
    }
  }, [conversations, hasRestoredState]);

  useEffect(() => {
    try {
      localStorage.setItem(
        OPEN_CONVERSATIONS_STORAGE_KEY,
        JSON.stringify({
          openConversations: openConversations.map((conversation) => ({
            id: conversation.id,
            collapsed: Boolean(conversation.collapsed),
          })),
          collapsed,
          showOnlyAvatar,
        })
      );
    } catch {
      // ignore storage failures
    }
  }, [openConversations, collapsed, showOnlyAvatar]);

  const handleOpenConversation = (conversation: OpenConversation) => {
    setOpenConversations((current) => {
      if (current.some((item) => item.id === conversation.id)) {
        return current;
      }
      return [...current, { ...conversation, collapsed: false }];
    });
    setCollapsed(false);
  };

  const handleCloseConversation = (conversationId: string) => {
    setOpenConversations((current) => current.filter((conversation) => conversation.id !== conversationId));
  };

  const handleToggleConversationListCollapsed = () => {
    setCollapsed((current) => !current);
  };

  const handleToggleShowOnlyAvatar = () => {
    setShowOnlyAvatar((current) => !current);
  };

  useEffect(() => {
    const handler = (event: Event) => {
      const custom = event as CustomEvent<OpenConversation>;
      const conversation = custom.detail;
      if (!conversation?.id) return;
      handleOpenConversation(conversation);
    };

    window.addEventListener('notalone:openConversation', handler);
    return () => {
      window.removeEventListener('notalone:openConversation', handler);
    };
  }, []);

  useChatSubscriptions(
    user?.id,
    token,
    (typingStatus) => {
      const sender = typingStatus.sender;
      setOpenConversations((current) =>
        current.map((conversation) =>
          conversation.id === sender.id ? { ...conversation, isTyping: typingStatus.isTyping } : conversation
        )
      );
    },
    (message) => {
      const sender = message.sender;
      setOpenConversations((current) =>
        current.map((conversation) =>
          conversation.id === sender.id ? { ...conversation, isTyping: false } : conversation
        )
      );
    }
  );

  const handleToggleConversationCollapsed = (conversationId: string) => {
    setOpenConversations((current) =>
      current.map((conversation) =>
        conversation.id === conversationId
          ? { ...conversation, collapsed: !Boolean(conversation.collapsed) }
          : conversation
      )
    );
  };

  return (
    <Box
      style={{
        position: 'fixed',
        right: 20,
        bottom: 20,
        zIndex: 999,
        display: 'flex',
        flexDirection: 'row',
        gap: 12,
        alignItems: 'flex-end',
      }}
    >
      {openConversations.map((conversation) => (
        <ChatComponent
          key={conversation.id}
          conversationId={conversation.id}
          avatar={conversation.avatar}
          username={conversation.username}
          lastMessage={conversation.lastMessage}
          collapsed={Boolean(conversation.collapsed)}
          isTyping={Boolean(conversation.isTyping)}
          onToggleCollapse={() => handleToggleConversationCollapsed(conversation.id)}
          onClose={() => handleCloseConversation(conversation.id)}
        />
      ))}
      {conversationsQuery.isLoading && <Loader size="sm" />}
      <ChatListComponent
        conversations={conversations}
        collapsed={collapsed}
        showOnlyAvatar={showOnlyAvatar}
        onToggle={handleToggleConversationListCollapsed}
        onToggleShowOnlyAvatar={handleToggleShowOnlyAvatar}
        onSelectConversation={handleOpenConversation}
      />
    </Box>
  );
}

import { Group, Text, Avatar, Stack, Menu, ActionIcon, Textarea, Button, Box } from '@mantine/core';
import Link from 'next/link';
import { useRouter } from 'next/router';
import { IconDotsVertical, IconPencil, IconTrash, IconX, IconCheck, IconFlag } from '@tabler/icons-react';
import { getUploadUrl } from '@/lib/uploads';
import { getTimeAgo, parseDate } from '@/lib/tools';
import CreateCommentComponent from '@/components/comments/CreateCommentComponent';
import DeleteCommentModal from '@/components/comments/DeleteCommentModal';
import { useAuth } from '@/contexts/AuthContext';
import { useState } from 'react';
import { useDeleteComment, useUpdateComment } from '@/hooks/useApi';
import { notifications } from '@mantine/notifications';
import type { Comment } from '@/types';

interface CommentComponentProps {
  comments: Comment[];
  postId: string;
  showCreate?: boolean;
  preview?: boolean;
}

export default function CommentComponent({ comments, postId, showCreate = false, preview = false }: CommentComponentProps) {
  const router = useRouter();
  const { user } = useAuth();
  const updateComment = useUpdateComment();
  const deleteComment = useDeleteComment();
  const [editingCommentId, setEditingCommentId] = useState<string | null>(null);
  const [editingContent, setEditingContent] = useState('');
  const [commentToDelete, setCommentToDelete] = useState<Comment | null>(null);

  const startEdit = (comment: Comment) => {
    setEditingCommentId(comment.id);
    setEditingContent(comment.content);
  };

  const cancelEdit = () => {
    setEditingCommentId(null);
    setEditingContent('');
  };

  const saveEdit = (commentId: string) => {
    if (!editingContent.trim()) return;
    updateComment.mutate(
      { id: commentId, content: editingContent },
      {
        onSuccess: () => {
          setEditingCommentId(null);
          setEditingContent('');
          notifications.show({ title: 'Commentaire modifi├®', message: 'Ton commentaire a ├®t├® mis ├á jour.', color: 'green' });
        },
        onError: (error: any) => {
          notifications.show({ title: 'Erreur', message: error?.message || 'Impossible de modifier le commentaire.', color: 'red' });
        },
      }
    );
  };

  const handleDelete = (commentId: string) => {
    setCommentToDelete(comments.find((comment) => comment.id === commentId) ?? null);
  };

  const handleReport = (commentId: string) => {
    notifications.show({
      title: 'Commentaire signal├®',
      message: 'Merci, nous allons examiner ce commentaire.',
      color: 'red',
    });
  };

  const handleModerate = (commentId: string) => {
    router.push(`/admin/moderate/comment/${commentId}`);
  };

  const confirmDelete = (commentId: string) => {
    deleteComment.mutate(
      { id: commentId },
      {
        onSuccess: () => {
          setCommentToDelete(null);
          notifications.show({ title: 'Commentaire supprim├®', message: 'Le commentaire a bien ├®t├® supprim├®.', color: 'green' });
        },
        onError: (error: any) => {
          notifications.show({ title: 'Erreur', message: error?.message || 'Impossible de supprimer le commentaire.', color: 'red' });
        },
      }
    );
  };

  return (
    <Stack gap="sm" mt="md" pt="md" style={{ borderTop: '1px solid #EAF7FF' }}>
      {comments.map((comment) => {
        const canManage = !preview && user?.id === comment.author.id;
        const isEditing = editingCommentId === comment.id;
        return (
          <Group key={comment.id} gap="sm" align="flex-start" style={{ width: '100%', minWidth: 0 }}>
            <Link href={`/profile/${comment.author.id}`} legacyBehavior>
              <a style={{ display: 'inline-block' }}>
                <Avatar src={getUploadUrl(comment.author.avatar) || '/default-avatar.svg'} size="sm" radius="xl" color="pastelBlue">
                  {comment.author.username.charAt(0).toUpperCase()}
                </Avatar>
              </a>
            </Link>
            <Box style={{ flex: 1, minWidth: 0, display: 'flex', flexDirection: 'column' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', width: '100%', marginBottom: 8, flexWrap: 'wrap' }}>
                <Group gap="xs" style={{ minWidth: 0, flex: 1 }}>
                  <Text size="sm" fw={600} style={{ minWidth: 0 }}>
                    <Link href={`/profile/${comment.author.id}`} legacyBehavior>
                      <a style={{ color: 'inherit', textDecoration: 'none' }}>@{comment.author.username}</a>
                    </Link>
                  </Text>
                  <Text size="xs" c="dimmed">
                    {getTimeAgo(parseDate(comment.createdAt))}
                  </Text>
                </Group>
                <div style={{ marginLeft: 'auto', flexShrink: 0 }}>
                  <Menu withinPortal position="bottom-end" shadow="sm">
                    <Menu.Target>
                      <ActionIcon variant="subtle" color="gray">
                        <IconDotsVertical size={18} />
                      </ActionIcon>
                    </Menu.Target>
                    <Menu.Dropdown>
                      <Menu.Item color="red" leftSection={<IconFlag size={16} />} onClick={() => handleReport(comment.id)}>
                        Signaler
                      </Menu.Item>
                      {canManage && (
                        <>
                          <Menu.Item onClick={() => startEdit(comment)}>
                            <Group gap="xs" align="center">
                              <IconPencil size={16} />
                              Modifier
                            </Group>
                          </Menu.Item>
                          <Menu.Item onClick={() => handleDelete(comment.id)}>
                            <Group gap="xs" align="center">
                              <IconTrash size={16} />
                              Supprimer
                            </Group>
                          </Menu.Item>
                        </>
                      )}
                      {user?.role === 'ADMIN' && (
                        <Menu.Item onClick={() => handleModerate(comment.id)}>
                          <Group gap="xs" align="center">
                            <IconFlag size={16} />
                            Mod├®rer ce message
                          </Group>
                        </Menu.Item>
                      )}
                    </Menu.Dropdown>
                  </Menu>
                </div>
              </div>
              {isEditing ? (
                <div>
                  <Textarea
                    value={editingContent}
                    onChange={(event) => setEditingContent(event.currentTarget.value)}
                    autosize
                    minRows={2}
                    maxRows={6}
                    mb="xs"
                  />
                  <Group gap="xs" mt="xs">
                    <Button size="xs" variant="outline" onClick={cancelEdit}>
                      <IconX size={14} style={{ marginRight: 8 }} />
                      Annuler
                    </Button>
                    <Button size="xs" color="pastelBlue" onClick={() => saveEdit(comment.id)} loading={updateComment.isPending}>
                      <IconCheck size={14} style={{ marginRight: 8 }} />
                      Sauvegarder
                    </Button>
                  </Group>
                </div>
              ) : (
                <Text size="sm" style={{ whiteSpace: 'pre-wrap' }}>{comment.content}</Text>
              )}
            </Box>
          </Group>
        );
      })}
      {showCreate ? <CreateCommentComponent postId={postId} /> : null}
      <DeleteCommentModal
        opened={Boolean(commentToDelete)}
        onClose={() => setCommentToDelete(null)}
        comment={commentToDelete}
        postId={postId}
        onConfirm={() => commentToDelete && confirmDelete(commentToDelete.id)}
      />
    </Stack>
  );
}

import { useState } from 'react';
import { Group, Textarea, Button } from '@mantine/core';
import { notifications } from '@mantine/notifications';
import { useCreateComment } from '@/hooks/useApi';

interface CreateCommentComponentProps {
