  const handleSubmit = () => {
    if (!commentText.trim()) return;
    createComment.mutate(
      { postId, content: commentText },
      {
        onSuccess: () => {
          setCommentText('');
          notifications.show({ title: 'Commentaire ajout├®', message: 'Merci pour ton soutien ! ­ƒºí', color: 'green' });
        },
        onError: (error: any) => {
          notifications.show({ title: 'Erreur', message: error?.message || 'Impossible d\'envoyer le commentaire.', color: 'red' });
