import { notifications } from '@mantine/notifications';
import { useEffect, useRef, useState } from 'react';
import OGPreviewCreatePostComponent, { OgPreviewData } from '@/components/posts/OGPreviewCreatePostComponent';

const moodOptions = [
  { value: 'happy', label: '­ƒÿè Content(e)' },
  { value: 'grateful', label: '­ƒÖÅ Reconnaissant(e)' },
  { value: 'hopeful', label: '­ƒîƒ Plein(e) d\'espoir' },
