import { useEffect, useMemo, useRef } from 'react';
import { Center, Loader, Stack, Card, Text, Alert } from '@mantine/core';
import PostCard from './PostCard';
import { usePosts, useCommentSubscriptions, usePostSubscriptions } from '@/hooks/useApi';
import { useAuth } from '@/contexts/AuthContext';
import type { Post as PostType } from '@/types';

type FeedComponentProps = {
  posts?: PostType[];
  userId?: string;
  isLoading?: boolean;
  error?: unknown;
  fetchNextPage?: () => void;
  hasNextPage?: boolean;
  isFetchingNextPage?: boolean;
  emptyStateMessage?: string;
};

export default function FeedComponent({
  posts: externalPosts,
  userId,
  isLoading: externalLoading,
  error: externalError,
  fetchNextPage,
  hasNextPage,
  isFetchingNextPage,
  emptyStateMessage = 'Pas encore de posts. Sois le premier ├á partager ! ­ƒîƒ',
}: FeedComponentProps) {
  const isControlled = Array.isArray(externalPosts);
  const {
    data: internalData,
    isLoading: internalLoading,
    error: internalError,
    fetchNextPage: internalFetchNextPage,
    hasNextPage: internalHasNextPage,
    isFetchingNextPage: internalIsFetchingNextPage,
  } = usePosts(20, !isControlled);

  const posts = useMemo(() => {
    if (isControlled) return externalPosts ?? [];
    const pages = ((internalData as any)?.pages ?? []) as Array<{ posts: PostType[] }>;
    return pages.flatMap((page) => page.posts);
  }, [externalPosts, internalData, isControlled]);

  const { token } = useAuth();
  useCommentSubscriptions(token, userId);
  usePostSubscriptions(token, userId);

  const isLoading = isControlled ? externalLoading : internalLoading;
  const error = isControlled ? externalError : internalError;
  const hasError = Boolean(error);
  const fetchMore = isControlled ? fetchNextPage : internalFetchNextPage;
  const hasMore = isControlled ? hasNextPage : internalHasNextPage;
  const loadingMore = isControlled ? isFetchingNextPage : internalIsFetchingNextPage;
  const showEndMessage = posts.length > 0 && !loadingMore && (hasMore === false || (isControlled && !fetchMore));

  const loaderRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    if (!loaderRef.current || !fetchMore || !hasMore) return;

    const observer = new IntersectionObserver(
      (entries) => {
        if (entries[0].isIntersecting && hasMore) {
          fetchMore();
        }
      },
      { rootMargin: '200px' }
    );

    observer.observe(loaderRef.current);
    return () => observer.disconnect();
  }, [fetchMore, hasMore]);

  return (
    <Stack gap="xl">
      {isLoading && (
        <Center py="xl">
          <Loader color="pastelBlue" size="lg" />
        </Center>
      )}

      {hasError && (
        <Alert color="red" title="Erreur">
          Impossible de charger les posts. V├®rifie que le serveur est bien lanc├®.
        </Alert>
      )}

      {posts.length === 0 && !isLoading && !hasError && (
        <Card padding="xl" radius="lg" withBorder style={{ borderColor: '#FFE8CC' }}>
          <Text ta="center" c="dimmed" size="lg">
            {emptyStateMessage}
          </Text>
        </Card>
      )}

      {posts.map((post) => (
        <PostCard key={post.id} post={post} />
      ))}

      <div ref={loaderRef} />

      {loadingMore && (
        <Center py="xl">
          <Loader color="pastelBlue" size="lg" />
        </Center>
      )}

      {showEndMessage && (
        <Card padding="md" radius="lg" withBorder style={{ borderColor: '#FFE8CC' }}>
          <Text ta="center" c="dimmed" size="sm">
            Pas de posts suppl├®mentaires
          </Text>
        </Card>
      )}
    </Stack>
  );
}

import { Card, Text, Image, CloseButton, Skeleton } from '@mantine/core';
import { useEffect, useState } from 'react';

export interface OgPreviewData {
  url: string;
  title: string;
  description: string;
  image?: string;
  siteName?: string;
}

interface OGPreviewCreatePostComponentProps {
  url: string | null;
  hiddenUrl: string | null;
  onPreviewChange: (preview: OgPreviewData | null) => void;
  onClose: () => void;
}

const apiBase = (process.env.NEXT_PUBLIC_API_URL?.replace(/\/graphql\/?$/, '') || 'http://localhost:4000');

export default function OGPreviewCreatePostComponent({ url, hiddenUrl, onPreviewChange, onClose }: OGPreviewCreatePostComponentProps) {
  const [preview, setPreview] = useState<OgPreviewData | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (!url || url === hiddenUrl) {
      setLoading(false);
      setPreview(null);
      setError(null);
      onPreviewChange(null);
      return;
    }

    const controller = new AbortController();
    const fetchPreview = async () => {
      setLoading(true);
      setError(null);
      try {
        const res = await fetch(`${apiBase}/api/og-preview?url=${encodeURIComponent(url)}`, {
          signal: controller.signal,
        });
        if (!res.ok) {
          const body = await res.json().catch(() => null);
          throw new Error(body?.error || 'Impossible de charger lÔÇÖaper├ºu');
        }
        const data = await res.json();
        if (!data.title && !data.description && !data.image) {
          throw new Error('Aucun aper├ºu disponible');
        }

        const nextPreview: OgPreviewData = {
          url: data.url,
          title: data.title || data.siteName || data.url,
          description: data.description || '',
          image: data.image,
          siteName: data.siteName,
        };

        setPreview(nextPreview);
        onPreviewChange(nextPreview);
      } catch (err: any) {
        if (!controller.signal.aborted) {
          setError(err?.message || 'Impossible de r├®cup├®rer lÔÇÖaper├ºu');
          setPreview(null);
          onPreviewChange(null);
        }
      } finally {
        if (!controller.signal.aborted) {
          setLoading(false);
        }
      }
    };

    void fetchPreview();
    return () => {
      controller.abort();
    };
  }, [url, hiddenUrl, onPreviewChange]);

  if (!url || url === hiddenUrl) {
    return null;
  }

  if (loading) {
    return (
      <Card shadow="sm" padding="md" radius="md" withBorder>
        <Skeleton height={24} width="40%" radius="xl" mb="sm" />
        <Skeleton height={16} width="80%" radius="xl" mb="xs" />
        <Skeleton height={16} width="70%" radius="xl" />
      </Card>
    );
  }

  if (error) {
    return <Text size="xs" c="red">{error}</Text>;
  }

  if (!preview) {
    return null;
  }

  return (
    <Card shadow="sm" padding="md" radius="md" withBorder style={{ width: '100%', position: 'relative' }}>
      <CloseButton
        size="sm"
        style={{ position: 'absolute', right: 10, top: 10, zIndex: 1 }}
        onClick={onClose}
      />
      {preview.image ? (
        <Image src={preview.image} alt={preview.title} height={140} fit="cover" radius="md" style={{ marginBottom: 12 }} />
      ) : null}
      <Text fw={700} lineClamp={2} style={{ marginBottom: 4 }}>
        {preview.title}
      </Text>
      {preview.description ? (
        <Text size="sm" c="dimmed" lineClamp={3} style={{ marginBottom: 8 }}>
          {preview.description}
        </Text>
      ) : null}
      <Text size="xs" c="dimmed">
        {preview.siteName || new URL(preview.url).hostname}
      </Text>
    </Card>
  );
}

import { Card, Text } from '@mantine/core';
import { useEffect, useState, type MouseEvent } from 'react';

interface OGPreviewPostComponentProps {
  url: string | null;
  fallbackTitle?: string | null;
  fallbackDescription?: string | null;
  fallbackImage?: string | null;
  fallbackSiteName?: string | null;
}

const apiBase = (process.env.NEXT_PUBLIC_API_URL?.replace(/\/graphql\/?$/, '') || 'http://localhost:4000');

function getYouTubeVideoId(url: string): string | null {
  try {
    const parsed = new URL(url);
    if (parsed.hostname.includes('youtube.com')) {
      return parsed.searchParams.get('v');
    }
    if (parsed.hostname === 'youtu.be') {
      return parsed.pathname.slice(1);
    }
    return null;
  } catch {
    return null;
  }
}

export default function OGPreviewPostComponent({
  url,
  fallbackTitle,
  fallbackDescription,
  fallbackImage,
  fallbackSiteName,
}: OGPreviewPostComponentProps) {
  const [preview, setPreview] = useState<{ title?: string; description?: string; image?: string; siteName?: string } | null>(null);
  const [loading, setLoading] = useState(false);
  const [showPlayer, setShowPlayer] = useState(false);

  const youTubeId = url ? getYouTubeVideoId(url) : null;

  useEffect(() => {
    if (!url) {
      setPreview(null);
      setLoading(false);
      setShowPlayer(false);
      return;
    }

    const controller = new AbortController();
    const fetchPreview = async () => {
      setLoading(true);
      try {
        const res = await fetch(`${apiBase}/api/og-preview?url=${encodeURIComponent(url)}`, {
          signal: controller.signal,
        });
        if (!res.ok) {
          setPreview(null);
          return;
        }
        const data = await res.json();
        setPreview({
          title: data.title || undefined,
          description: data.description || undefined,
          image: data.image || undefined,
          siteName: data.siteName || undefined,
        });
      } catch {
        setPreview(null);
      } finally {
        if (!controller.signal.aborted) {
          setLoading(false);
        }
      }
    };

    void fetchPreview();
    return () => {
      controller.abort();
    };
  }, [url]);

  if (!url) {
    return null;
  }

  const previewTitle = preview?.title || fallbackTitle || url;
  const previewDescription = preview?.description || fallbackDescription || undefined;
  const previewImage = preview?.image || fallbackImage || undefined;
  const previewSiteName = preview?.siteName || fallbackSiteName || undefined;
  const isYoutube = Boolean(youTubeId);

  const handleClick = (event: MouseEvent<HTMLDivElement>) => {
    if (isYoutube) {
      event.preventDefault();
      setShowPlayer(true);
    }
  };

  if (isYoutube) {
    return (
      <Card
        onClick={handleClick}
        shadow="sm"
        padding="md"
        radius="md"
        withBorder
        style={{ marginBottom: 16, textDecoration: 'none', color: 'inherit', cursor: 'pointer' }}
      >
        {showPlayer && youTubeId ? (
          <div style={{ position: 'relative', paddingTop: '56.25%', marginBottom: 12 }}>
            <iframe
              src={`https://www.youtube.com/embed/${youTubeId}?autoplay=1&rel=0`}
              title={previewTitle}
              frameBorder="0"
              allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
              allowFullScreen
              style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', borderRadius: 12 }}
            />
          </div>
        ) : previewImage ? (
          <div style={{ overflow: 'hidden', borderRadius: 12, marginBottom: 12 }}>
            <img
              src={previewImage}
              alt={previewTitle}
              style={{ display: 'block', width: '100%', height: 140, objectFit: 'cover' }}
              onError={(event) => {
                (event.currentTarget as HTMLImageElement).style.display = 'none';
              }}
            />
          </div>
        ) : null}
        <Text fw={700} lineClamp={2} mb="xs">
          {previewTitle}
        </Text>
        {previewDescription ? (
          <Text size="sm" c="dimmed" lineClamp={3} mb="xs">
            {previewDescription}
          </Text>
        ) : null}
        <Text size="xs" c="dimmed">
          {previewSiteName || (() => {
            try {
              return new URL(url).hostname;
            } catch {
              return url;
            }
          })()}
        </Text>
      </Card>
    );
  }

  return (
    <Card
      component="a"
      href={url}
      target="_blank"
      rel="noreferrer noopener"
      shadow="sm"
      padding="md"
      radius="md"
      withBorder
      style={{ marginBottom: 16, textDecoration: 'none', color: 'inherit' }}
    >
      {previewImage ? (
        <div style={{ overflow: 'hidden', borderRadius: 12, marginBottom: 12 }}>
          <img
            src={previewImage}
            alt={previewTitle}
            style={{ display: 'block', width: '100%', height: 140, objectFit: 'cover' }}
            onError={(event) => {
              (event.currentTarget as HTMLImageElement).style.display = 'none';
            }}
          />
        </div>
      ) : null}
      <Text fw={700} lineClamp={2} mb="xs">
        {previewTitle}
      </Text>
      {previewDescription ? (
        <Text size="sm" c="dimmed" lineClamp={3} mb="xs">
          {previewDescription}
        </Text>
      ) : null}
      <Text size="xs" c="dimmed">
        {previewSiteName || (() => {
          try {
            return new URL(url).hostname;
          } catch {
            return url;
          }
        })()}
      </Text>
    </Card>
  );
}

import { Card, Group, Text, Avatar, ActionIcon, Stack, Badge, Menu, Textarea, Button } from '@mantine/core';
import Link from 'next/link';
import { useRouter } from 'next/router';
import { IconHeart, IconHeartFilled, IconMessageCircle, IconDotsVertical, IconPencil, IconTrash, IconFlag } from '@tabler/icons-react';
import { useToggleLike, useUpdatePost } from '@/hooks/useApi';
import { useAuth } from '@/contexts/AuthContext';
import { useState, useEffect } from 'react';
import { notifications } from '@mantine/notifications';
import { getUploadUrl } from '@/lib/uploads';
import ViewImageModal from '@/components/posts/ViewImageModal';
import AudioPlayer from '@/components/posts/AudioPlayer';
import OGPreviewPostComponent from '@/components/posts/OGPreviewPostComponent';
import DeletePostModal from '@/components/posts/DeletePostModal';
import CommentComponent from '@/components/comments/CommentComponent';
import { Post } from '@/types';
import { getTimeAgo, parseDate } from '@/lib/tools';

interface PostCardProps {
  post: Post;
  preview?: boolean;
}

const moodEmojis: Record<string, string> = {
  happy: '­ƒÿè',
  grateful: '­ƒÖÅ',
  hopeful: '­ƒîƒ',
  calm: '­ƒÿî',
  loved: '­ƒÑ░',
  strong: '­ƒÆ¬',
  anxious: '­ƒÿ░',
  sad: '­ƒÿó',
  lonely: '­ƒ½é',
  struggling: '­ƒîº´©Å',
};

export default function PostCard({ post, preview }: PostCardProps) {
  const router = useRouter();
  const { isAuthenticated, user } = useAuth();
  const isAdmin = user?.role === 'ADMIN';
  const canModifyPost = isAuthenticated && user?.id === post.author.id;
  const toggleLike = useToggleLike();
  const updatePost = useUpdatePost();
  const [showComments, setShowComments] = useState(() => (post.comments && post.comments.length > 0));
  const [deleteModalOpened, setDeleteModalOpened] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [editedContent, setEditedContent] = useState(post.content);
  const [content, setContent] = useState(post.content);

  useEffect(() => {
    setEditedContent(post.content);
    setContent(post.content);
  }, [post.content]);

  const handleLike = () => {
    if (!isAuthenticated) {
      notifications.show({ title: 'Connexion requise', message: 'Connecte-toi pour soutenir ce post', color: 'pastelBlue' });
      return;
    }
    toggleLike.mutate({ postId: post.id });
  };

  const handleDelete = () => {
    setDeleteModalOpened(true);
  };

  const handleReport = () => {
    notifications.show({
      title: 'Post signal├®',
      message: 'Merci de votre vigilance, nous allons examiner ce contenu.',
      color: 'red',
    });
  };

  const handleEdit = () => {
    setIsEditing(true);
  };

  const handleModerate = () => {
    router.push(`/admin/moderate/post/${post.id}`);
  };

  const handleSaveEdit = () => {
    if (!editedContent.trim()) {
      notifications.show({ title: 'Contenu vide', message: 'Le post ne peut pas ├¬tre vide.', color: 'red' });
      return;
    }

    updatePost.mutate(
      { id: post.id, content: editedContent },
      {
        onSuccess: () => {
          setContent(editedContent);
          setIsEditing(false);
          notifications.show({ title: 'Post modifi├®', message: 'Le contenu du post a ├®t├® mis ├á jour.', color: 'green' });
        },
        onError: (error: any) => {
          notifications.show({ title: 'Erreur', message: error?.message || 'Impossible de modifier le post.', color: 'red' });
        },
      }
    );
  };

  useEffect(() => {
    if (post.comments && post.comments.length > 0) setShowComments(true);
  }, [post.comments]);

  const displayName = post.author.firstName
    ? `${post.author.firstName} ${post.author.lastName || ''}`.trim()
    : post.author.username;

  const timeAgo = getTimeAgo(parseDate(post.createdAt));

  const [imageModalOpen, setImageModalOpen] = useState(false);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);

  const linkedPreviewUrl = typeof post.payload?.linkedUrl === 'string' && post.payload.linkedUrl.trim() ? String(post.payload.linkedUrl) : null;
  const linkedPreviewImage = typeof post.payload?.linkedImage === 'string' && post.payload.linkedImage.trim() ? String(post.payload.linkedImage) : null;
  const linkedPreviewTitle = typeof post.payload?.linkedTitle === 'string' && post.payload.linkedTitle.trim() ? String(post.payload.linkedTitle) : linkedPreviewUrl;
  const linkedPreviewDescription = typeof post.payload?.linkedDescription === 'string' ? String(post.payload.linkedDescription) : null;
  const linkedPreviewSiteName = typeof post.payload?.linkedSiteName === 'string' && post.payload.linkedSiteName.trim() ? String(post.payload.linkedSiteName) : null;

  return (
    <Card shadow="sm" padding="lg" radius="lg" withBorder style={{ borderColor: '#EAF7FF' }}>
      <Group justify="space-between" mb="sm">
        <Group>
          <Link href={`/profile/${post.author.id}`} style={{ display: 'inline-block' }}>
            <Avatar src={getUploadUrl(post.author.avatar) || '/default-avatar.svg'} alt={post.author.username} radius="xl" color="pastelBlue">
              {post.author.username.charAt(0).toUpperCase()}
            </Avatar>
          </Link>
          <div>
            <Text fw={600} size="sm">
              <Link href={`/profile/${post.author.id}`} style={{ color: 'inherit', textDecoration: 'none' }}>
                {displayName}
              </Link>
            </Text>
            <Text size="xs" c="dimmed">
              <Link href={`/profile/${post.author.id}`} style={{ color: 'inherit', textDecoration: 'none' }}>
                @{post.author.username}
              </Link>
              {' ┬À '}
              <Link href={`/posts/${post.id}`} style={{ color: 'inherit', textDecoration: 'underline' }}>
                {timeAgo}
              </Link>
            </Text>
          </div>
        </Group>
        {post.mood && (
          <Badge variant="light" color="pastelBlue" size="lg">
            {moodEmojis[post.mood] || '­ƒÆ¡'} {post.mood}
          </Badge>
        )}
        {!preview && (
        <Menu withinPortal position="bottom-end" shadow="sm">
          <Menu.Target>
            <ActionIcon variant="subtle" color="gray">
              <IconDotsVertical size={20} />
            </ActionIcon>
          </Menu.Target>
          <Menu.Dropdown>
            <Menu.Item color="red" onClick={handleReport} leftSection={<IconFlag size={16} />}>
              Signaler
            </Menu.Item>
            {canModifyPost && (
              <>
                <Menu.Item onClick={handleEdit}>
                  <Group gap="xs" align="center">
                    <IconPencil size={16} />
                    Modifier
                  </Group>
                </Menu.Item>
                <Menu.Item onClick={handleDelete}>
                  <Group gap="xs" align="center">
                    <IconTrash size={16} />
                    Supprimer
                  </Group>
                </Menu.Item>
              </>
            )}
            {isAdmin && (
              <Menu.Item onClick={handleModerate}>
                <Group gap="xs" align="center">
                  <IconFlag size={16} />
                  Mod├®rer ce message
                </Group>
              </Menu.Item>
            )}
          </Menu.Dropdown>
        </Menu>
        )}
      </Group>

      {!preview && (
      <DeletePostModal opened={deleteModalOpened} onClose={() => setDeleteModalOpened(false)} post={post} />
      )}
      {isEditing ? (
        <div style={{ marginBottom: 16 }}>
          <Textarea
            value={editedContent}
            onChange={(event) => setEditedContent(event.currentTarget.value)}
            autosize
            minRows={3}
            maxRows={8}
            mb="sm"
          />
          <Button size="sm" color="pastelBlue" onClick={handleSaveEdit} loading={updatePost.isPending}>
            Modifier
          </Button>
        </div>
      ) : (
        <Text size="md" mb="md" style={{ whiteSpace: 'pre-wrap', lineHeight: 1.6 }}>
          {content}
        </Text>
      )}

      {linkedPreviewUrl ? (
        <OGPreviewPostComponent
          url={linkedPreviewUrl}
          fallbackTitle={linkedPreviewTitle}
          fallbackDescription={linkedPreviewDescription || undefined}
          fallbackImage={linkedPreviewImage || undefined}
          fallbackSiteName={linkedPreviewSiteName || undefined}
        />
      ) : null}

      {post.attachments && post.attachments.length > 0 && (
        <Stack gap="xs" mb="md">
          {post.attachments.map((a) => (
            <div key={a.id}>
              {a.mimeType?.startsWith('image/') ? (
                // eslint-disable-next-line @next/next/no-img-element
                <img
                  src={getUploadUrl(a.path)}
                  alt={a.filename}
                  style={{ maxWidth: '100%', borderRadius: 8, cursor: 'pointer' }}
                  onClick={() => {
                    setSelectedImage(a.path);
                    setImageModalOpen(true);
                  }}
                />
              ) : a.mimeType?.startsWith('audio/') ? (
                <AudioPlayer src={a.path} filename={a.filename} />
              ) : (
                <a href={getUploadUrl(a.path)} target="_blank" rel="noreferrer">{a.filename}</a>
              )}
            </div>
          ))}
        </Stack>
      )}

      <ViewImageModal
        opened={imageModalOpen}
        onClose={() => setImageModalOpen(false)}
        imageSrc={selectedImage || ''}
        post={post}
      />

      <Group justify="space-between">
        <Group gap="lg">
          <Group gap={4}>
            <ActionIcon
              variant="subtle"
              color={post.isLikedByMe ? 'red' : 'gray'}
              onClick={handleLike}
              loading={toggleLike.isPending}
              disabled={preview}
            >
              {post.isLikedByMe ? <IconHeartFilled size={20} /> : <IconHeart size={20} />}
            </ActionIcon>
            <Text size="sm" c="dimmed">
              {post.likesCount}
            </Text>
          </Group>
          <Group gap={4}>
            <ActionIcon variant="subtle" color="gray" 
              disabled={preview} onClick={() => setShowComments(!showComments)}>
              <IconMessageCircle size={20} />
            </ActionIcon>
            <Text size="sm" c="dimmed">
              {post.commentsCount}
            </Text>
          </Group>
        </Group>
      </Group>

      {showComments && (
        <CommentComponent
          comments={post.comments}
          postId={post.id}
          showCreate={!preview && isAuthenticated}
        />
      )}
    </Card>
  );
}

import { Modal, Group, Image, Stack, Text, Avatar, Divider, Textarea, Button, ScrollArea, ActionIcon } from '@mantine/core';
import { useState, useEffect } from 'react';
import { useCreateComment, useToggleLike } from '@/hooks/useApi';
import { Comment, Post } from '@/types';
import { useAuth } from '@/contexts/AuthContext';
import { getUploadUrl } from '@/lib/uploads';
import { IconHeart, IconHeartFilled } from '@tabler/icons-react';
import { notifications } from '@mantine/notifications';
import { getTimeAgo, parseDate } from '@/lib/tools';

interface ViewImageModalProps {
  opened: boolean;
  onClose: () => void;
  imageSrc: string;
  post?: Post;
}

export default function ViewImageModal({ opened, onClose, imageSrc, post }: ViewImageModalProps) {
  const [localComments, setLocalComments] = useState<Comment[]>(post?.comments || []);
  const [newComment, setNewComment] = useState('');
  const [naturalSize, setNaturalSize] = useState({ w: 0, h: 0 });
  const [displaySize, setDisplaySize] = useState({ w: 0, h: 0 });
  const [modalSize, setModalSize] = useState({ w: 'auto', h: '70vh' });
  const createComment = useCreateComment();
  const { isAuthenticated } = useAuth();
  const toggleLike = useToggleLike();
  
  useEffect(() => {
    setLocalComments(post?.comments || []);
  }, [post]);

    
      const handleLike = () => {
        if (!isAuthenticated) {
          notifications.show({ title: 'Connexion requise', message: 'Connecte-toi pour soutenir ce post', color: 'pastelBlue' });
          return;
        }
        toggleLike.mutate({ postId: post?.id! });
      };

  useEffect(() => {
    function computeSizes() {
      const sidebarWidth = 420; // right panel
      const spacing = 48; // Group spacing + paddings

      const vw = typeof window !== 'undefined' ? window.innerWidth : 1200;
      const vh = typeof window !== 'undefined' ? window.innerHeight : 800;

      const maxModalWidth = Math.floor(vw * 0.95);
      const maxModalHeight = Math.floor(vh * 0.9);

      const maxImageWidth = Math.max(100, maxModalWidth - sidebarWidth - spacing);
      const maxImageHeight = Math.max(100, maxModalHeight - 40);

      const nw = naturalSize.w || maxImageWidth;
      const nh = naturalSize.h || maxImageHeight;

      const scale = Math.min(1, maxImageWidth / nw, maxImageHeight / nh);

      const dw = Math.floor(nw * scale);
      const dh = Math.floor(nh * scale);

      const totalW = Math.min(maxModalWidth, dw + sidebarWidth + spacing);
      const totalH = Math.min(maxModalHeight, Math.max(dh, 420));

      setDisplaySize({ w: dw, h: dh });
      setModalSize({ w: `${totalW}px`, h: `${totalH}px` });
    }

    computeSizes();
    window.addEventListener('resize', computeSizes);
    return () => window.removeEventListener('resize', computeSizes);
  }, [naturalSize]);

  async function handleAddComment() {
    if (!newComment.trim()) return;
    if (!post?.id) {
      const temp = { id: `tmp-${Date.now()}`, content: newComment.trim(), createdAt: new Date().toISOString(), author: { id: 'me', username: 'Moi' } } as Comment
      setLocalComments((c) => [temp, ...c]);
      setNewComment('');
      return;
    }

    try {
      const res = await createComment.mutateAsync({ postId: post.id, content: newComment.trim() } as any);
      const created = (res as any).createComment as Comment;
      setLocalComments((c) => [created, ...c]);
      setNewComment('');
    } catch (e) {
      console.error('add comment error', e);
    }
  }

  return (
    <Modal
      opened={opened}
      onClose={onClose}
      size="auto"
      centered
      withCloseButton={false}
      padding={0}
      styles={{ header: { display: 'none' }, content: { overflow: 'hidden', width: modalSize.w, height: modalSize.h } }}
    >
      <Group align="stretch" gap="xl" style={{ maxHeight: modalSize.h, height: modalSize.h }}>
        <div style={{ flex: '0 0 auto', display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: 0, overflow: 'hidden' }}>
          <Image
            src={getUploadUrl(imageSrc) || imageSrc}
            alt="attachment"
            fit="contain"
            onLoad={(e) => {
              const img = e.currentTarget as HTMLImageElement;
              setNaturalSize({ w: img.naturalWidth, h: img.naturalHeight });
            }}
            style={{ display: 'block', width: displaySize.w ? `${displaySize.w}px` : 'auto', height: displaySize.h ? `${displaySize.h}px` : 'auto', objectFit: 'contain' }}
          />
        </div>

        <div style={{ width: 420, display: 'flex', flexDirection: 'column', height: '100%' }}>
          <Stack gap="sm" style={{ padding: 12, flex: '0 0 auto' }}>
            <Group gap="sm">
              <Avatar src={getUploadUrl(post?.author?.avatar) || '/default-avatar.svg'} radius="xl" />
              <div>
                <Text fw={700}>{post?.author?.username ?? 'Utilisateur'}</Text>
                <Text size="xs" c="dimmed">{ getTimeAgo(parseDate(post?.createdAt as string))}</Text>
              </div>
            </Group>

            <Divider />

            <Text style={{ whiteSpace: 'pre-wrap' }}>{post?.content}</Text>
          </Stack>

          <Divider />

          <div style={{ padding: 12, flex: '1 1 auto', display: 'flex', flexDirection: 'column' }}>
            <ScrollArea style={{ flex: 1 }} type="always">
              <Stack gap="sm">
                {localComments.map((c) => (
                  <Group key={c.id} gap="sm" align="flex-start">
                    <Avatar src={getUploadUrl(c.author.avatar) || '/default-avatar.svg'} radius="xl" size="sm" />
                    <div style={{ flex: 1 }}>
                      <Text fw={600}>{c.author.username}</Text>
                      <Text size="sm" c="dimmed">{ getTimeAgo(parseDate(c.createdAt))}</Text>
                      <Text style={{ whiteSpace: 'pre-wrap' }}>{c.content}</Text>
                    </div>
                  </Group>
                ))}
              </Stack>
            </ScrollArea>

            <div style={{ marginTop: 8 }}>
              {isAuthenticated ? (
                <div>
                    <Group gap={4}>
                        <ActionIcon
                          variant="subtle"
                          color={(post?.isLikedByMe) ? 'red' : 'gray'}
                          onClick={handleLike}
                          loading={toggleLike.isPending}
                          >
                          {post?.isLikedByMe ? <IconHeartFilled size={20} /> : <IconHeart size={20} />}
                          </ActionIcon>
                          <Text size="sm" c="dimmed">
                          {post?.likesCount}
                          </Text>
                    </Group>
                  <Textarea value={newComment} onChange={(e) => setNewComment(e.currentTarget.value)} placeholder="├ëcris un message de soutien..." autosize minRows={2} />
                  <Group align="right" mt="xs">
                    <Button onClick={handleAddComment} loading={createComment.isPending}>Envoyer</Button>
                  </Group>
                </div>
              ) : (
                <Text size="sm" c="dimmed">Connecte-toi pour laisser un commentaire.</Text>
              )}
            </div>
          </div>
        </div>
      </Group>
    </Modal>
  );
}

import { useEffect } from 'react';
import { useInfiniteQuery, useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { graphqlClient } from '@/lib/graphql-client';
import { createClient } from 'graphql-ws';
import { useRouter } from 'next/router';
import { notifications as mantineNotifications } from '@mantine/notifications';
import type {
  User,
  Post as PostType,
  Attachment as AttachmentType,
  Comment as CommentType,
  Like,
  Message,
  Conversation,
  AuthPayload,
  Notification,
  TypingStatus,
} from '@/types';
import { getNotificationText } from '@/lib/tools';
import { gql } from 'graphql-request';

type Comment = CommentType;

// --- Auth Queries ---

const LOGIN_MUTATION = gql`
  mutation Login($identifier: String!, $password: String!) {
    login(identifier: $identifier, password: $password) {
      token
      user {
        id
        email
        username
        firstName
        lastName
        bio
        avatar
        role
      }
    }
  }
`;

const REGISTER_MUTATION = gql`
  mutation Register($email: String!, $username: String!, $password: String!, $firstName: String, $lastName: String) {
    register(email: $email, username: $username, password: $password, firstName: $firstName, lastName: $lastName) {
      token
      user {
        id
        email
        username
        firstName
        lastName
        bio
        avatar
        role
      }
    }
  }
`;

const ME_QUERY = gql`
  query Me {
    me {
      id
      email
      username
      firstName
      lastName
      role
      bio
      avatar
    }
  }
`;

// --- Post Queries ---

const POSTS_QUERY = gql`
  query Posts($limit: Int, $offset: Int) {
    posts(limit: $limit, offset: $offset) {
      id
      content
      mood
      isPublic
      payload
      createdAt
      attachments { id filename path mimeType size createdAt data }
      likesCount
      commentsCount
      isLikedByMe
      author {
        id
        username
        firstName
        lastName
        avatar
      }
      comments {
        id
        content
        createdAt
        author {
          id
          username
          avatar
        }
      }
    }
  }
`;

const CREATE_POST_MUTATION = gql`
  mutation CreatePost($content: String!, $mood: String, $isPublic: Boolean, $attachmentIds: [ID!], $payload: JSON) {
    createPost(content: $content, mood: $mood, isPublic: $isPublic, attachmentIds: $attachmentIds, payload: $payload) {
      id
      content
      mood
      isPublic
      payload
      createdAt
      attachments { id filename path mimeType size createdAt data }
      likesCount
      commentsCount
      isLikedByMe
      author {
        id
        username
        firstName
        lastName
        avatar
      }
    }
  }
`;

const UPDATE_POST_MUTATION = gql`
  mutation UpdatePost($id: ID!, $content: String!) {
    updatePost(id: $id, content: $content) {
      id
      content
      mood
      isPublic
      payload
      createdAt
      attachments { id filename path mimeType size createdAt data }
      likesCount
      commentsCount
      isLikedByMe
      author {
        id
        username
        firstName
        lastName
        avatar
      }
      comments {
        id
        content
        createdAt
        author {
          id
          username
          avatar
        }
      }
      likes {
        id
        user {
          id
          username
          avatar
        }
        createdAt
      }
    }
  }
`;

const POST_QUERY = gql`
  query Post($id: ID!) {
    post(id: $id) {
      id
      content
      mood
      isPublic
      payload
      createdAt
      attachments { id filename path mimeType size createdAt data }
      likesCount
      commentsCount
      isLikedByMe
      author { id username firstName lastName avatar }
      comments { id content createdAt author { id username avatar } }
    }
  }
`;

const TOGGLE_LIKE_MUTATION = gql`
  mutation ToggleLike($postId: ID!) {
    toggleLike(postId: $postId)
  }
`;

const DELETE_POST_MUTATION = gql`
  mutation DeletePost($id: ID!) {
    deletePost(id: $id)
  }
`;

const CREATE_COMMENT_MUTATION = gql`
  mutation CreateComment($postId: ID!, $content: String!) {
    createComment(postId: $postId, content: $content) {
      id
      content
