  const { isAuthenticated } = useAuth();



  if (isLoading) {
    return (
      <Layout>
        <Center py="xl">
          <Loader />
        </Center>
      </Layout>
    );
  }

  const user = data?.user;

  return (
    <Layout>
      <Head>
