              <Stack align="center">
                <Avatar src={getUploadUrl(user.avatar) || '/default-avatar.svg'} size={100} radius="xl" color="pastelBlue" variant="filled">
                  {user.username?.charAt(0).toUpperCase()}
                </Avatar>
                <Title order={2}>@{user.username}</Title>
                {user.firstName || user.lastName ? <Text c="dimmed">{`${user.firstName || ''} ${user.lastName || ''}`.trim()}</Text> : null}
                {user.bio && <Text>{user.bio}</Text>}
                <Text size="sm" c="dimmed">Membre depuis: {user.createdAt ? new Date(user.createdAt).toLocaleDateString('fr-FR') : 'ÔÇö'}</Text>
                {isAuthenticated && (
                  <Button
                    onClick={() => {
                      if (typeof window === 'undefined') return;
                      const avatar = getUploadUrl(user.avatar) || '';
                      window.dispatchEvent(
                        new CustomEvent('notalone:openConversation', {
                          detail: {
                            id: user.id,
                            username: user.username,
                            avatar,
                            lastMessage: '',
                            lastMessageAt: new Date().toISOString(),
                            unreadCount: 0,
                          },
                        })
                      );
                    }}
                  >
                    Envoyer un message
                  </Button>
                )}
              </Stack>
            </Card>

            <Stack gap="md">
              <Title order={3}>Posts</Title>
              <FeedComponent
                userId={user?.id}
                posts={(user as any).posts ?? []}
                emptyStateMessage="Cet utilisateur n'a pas encore partag├® de post."
              />
            </Stack>
          </Stack>
        )}
      </Container>
    </Layout>
  );
}

